1	import {
2	  Injectable,
3	  NotFoundException,
4	  BadRequestException,
5	  ForbiddenException,
6	} from '@nestjs/common';
7	import { InjectRepository } from '@nestjs/typeorm';
8	import { Repository, DataSource } from 'typeorm';
9	import { Paper } from './entities/paper.entity';
10	import { PaperQuestion } from './entities/paper-question.entity';
11	import { Attempt, AttemptStatus } from './entities/attempt.entity';
12	import { AttemptAnswer } from './entities/attempt-answer.entity';
13	import { Question, QuestionStatus, QuestionType } from '../questions/entities/question.entity';
14	import { QuestionOption } from '../questions/entities/question-option.entity';
15	import { GeneratePaperDto } from './dto/generate-paper.dto';
16	import { SubmitAnswerDto } from './dto/submit-attempt.dto';
17	
18	@Injectable()
19	export class AssessmentsService {
20	  constructor(
21	    @InjectRepository(Paper)
22	    private readonly paperRepo: Repository<Paper>,
23	    @InjectRepository(PaperQuestion)
24	    private readonly paperQuestionRepo: Repository<PaperQuestion>,
25	    @InjectRepository(Attempt)
26	    private readonly attemptRepo: Repository<Attempt>,
27	    @InjectRepository(AttemptAnswer)
28	    private readonly answerRepo: Repository<AttemptAnswer>,
29	    @InjectRepository(Question)
30	    private readonly questionRepo: Repository<Question>,
31	    @InjectRepository(QuestionOption)
32	    private readonly optionRepo: Repository<QuestionOption>,
33	    private readonly dataSource: DataSource,
34	  ) {}
35	
36	  /**
37	   * Resolves the effective store scope for a caller.
38	   *
39	   * - store_admin  → their assigned store id (403 if none is assigned)
40	   * - everyone else → null (no scope restriction applied)
41	   *
42	   * This is the single place in the service where we decide whether a
43	   * query needs to be tenant-scoped. Returning null for non-store-admin
44	   * preserves platform_admin, content_reviewer, and auditor behavior
45	   * exactly; returning the assigned id for store_admin is what closes
46	   * the cross-store paper read leak.
47	   */
48	  private resolveStoreScope(user?: any): string | null {
49	    if (user?.role === 'store_admin') {
50	      const storeId = user?.storeId ?? user?.store_id ?? null;
51	      if (!storeId) {
52	        throw new ForbiddenException('Store admin has no assigned store');
53	      }
54	      return storeId;
55	    }
56	    return null;
57	  }
58	
59	  /**
60	   * Ownership guard for per-paper reads. For store_admin callers, the
61	   * paper must live in their own store — otherwise we throw 404 (not
62	   * 403) so the existence of cross-store papers isn't leaked through
63	   * the status code, matching the tenant-isolation hiding policy used
64	   * by the questions module.
65	   */
66	  private enforcePaperOwnership(paper: Paper, user?: any): void {
67	    const scope = this.resolveStoreScope(user);
68	    if (scope && paper.store_id !== scope) {
69	      throw new NotFoundException('Paper not found');
70	    }
71	  }
72	
73	  /**
74	   * Resolves the effective target store for a generate-paper call.
75	   *
76	   * - store_admin: ALWAYS uses the JWT's assigned store. Any caller-supplied
77	   *   `?storeId=` is silently ignored — trusting it would re-introduce the
78	   *   cross-store paper-write tenant escape this method is hardened against.
79	   * - platform_admin / content_reviewer: may optionally target a specific
80	   *   store via the query param; falsy means "no scope filter".
81	   * - Other roles fall through to the same null-scope behavior, but the
82	   *   controller's @Roles decorator already restricts who can call this.
83	   */
84	  private resolveTargetStoreForGenerate(
85	    user: any,
86	    requestedStoreId?: string,
87	  ): string | null {
88	    if (user?.role === 'store_admin') {
89	      const jwtStoreId = user?.storeId ?? user?.store_id ?? null;
90	      if (!jwtStoreId) {
91	        throw new ForbiddenException('Store admin has no assigned store');
92	      }
93	      // Defensive: if a store_admin tries to target another store via the
94	      // query param, that's a tenant-escape attempt — refuse it loudly so
95	      // the audit trail captures it instead of silently succeeding.
96	      if (requestedStoreId && requestedStoreId !== jwtStoreId) {
97	        throw new ForbiddenException(
98	          'store_admin cannot generate papers for another store',
99	        );
100	      }
101	      return jwtStoreId;
102	    }
103	    return requestedStoreId ?? null;
104	  }
105	
106	  async generatePaper(
107	    dto: GeneratePaperDto,
108	    user: any,
109	    requestedStoreId?: string,
110	  ): Promise<Paper> {
111	    const storeId = this.resolveTargetStoreForGenerate(user, requestedStoreId);
112	    const userId: string = user?.id;
113	    const { generationRule } = dto;
114	    let questions: Question[];
115	
116	    if (generationRule.type === 'random') {
117	      const count = generationRule.count ?? 10;
118	      const qb = this.questionRepo
119	        .createQueryBuilder('q')
120	        .where('q.status = :status', { status: QuestionStatus.APPROVED });
121	
122	      if (storeId) {
123	        qb.andWhere('(q.store_id = :storeId OR q.store_id IS NULL)', {
124	          storeId,
125	        });
126	      }
127	
128	      questions = await qb
129	        .orderBy('RANDOM()')
130	        .limit(count)
131	        .getMany();
132	    } else {
133	      // rule-based
134	      const qb = this.questionRepo
135	        .createQueryBuilder('q')
136	        .where('q.status = :status', { status: QuestionStatus.APPROVED });
137	
138	      if (storeId) {
139	        qb.andWhere('(q.store_id = :storeId OR q.store_id IS NULL)', {
140	          storeId,
141	        });
142	      }
143	
144	      const filters = generationRule.filters ?? {};
145	      if (filters.type) {
146	        qb.andWhere('q.type = :type', { type: filters.type });
147	      }
148	
149	      const count = generationRule.count;
150	      if (count) {
151	        qb.limit(count);
152	      }
153	
154	      questions = await qb.getMany();
155	    }
156	
157	    const paper = this.paperRepo.create({
158	      name: dto.name,
159	      generation_rule: generationRule as any,
160	      created_by: userId,
161	      store_id: storeId ?? null,
162	    });
163	
164	    const savedPaper = await this.paperRepo.save(paper);
165	
166	    const paperQuestions = questions.map((q, index) =>
167	      this.paperQuestionRepo.create({
168	        paper_id: savedPaper.id,
169	        question_id: q.id,
170	        position: index + 1,
171	      }),
172	    );
173	
174	    await this.paperQuestionRepo.save(paperQuestions);
175	    savedPaper.paper_questions = paperQuestions;
176	
177	    return savedPaper;
178	  }
179	
180	  async startAttempt(paperId: string, userId: string): Promise<Attempt> {
181	    const paper = await this.paperRepo.findOne({ where: { id: paperId } });
182	    if (!paper) {
183	      throw new NotFoundException('Paper not found');
184	    }
185	
186	    const attempt = this.attemptRepo.create({
187	      paper_id: paperId,
188	      user_id: userId,
189	      status: AttemptStatus.IN_PROGRESS,
190	      started_at: new Date(),
191	    });
192	
193	    return this.attemptRepo.save(attempt);
194	  }
195	
196	  async submitAttempt(
197	    attemptId: string,
198	    answers: SubmitAnswerDto[],
199	    userId: string,
200	  ): Promise<Attempt> {
201	    const attempt = await this.attemptRepo.findOne({
202	      where: { id: attemptId },
203	    });
204	
205	    if (!attempt) {
206	      throw new NotFoundException('Attempt not found');
207	    }
208	
209	    if (attempt.user_id !== userId) {
210	      throw new BadRequestException('Attempt does not belong to this user');
211	    }
212	
213	    if (attempt.status !== AttemptStatus.IN_PROGRESS) {
214	      throw new BadRequestException('Attempt is not in progress');
215	    }
216	
217	    const now = new Date();
218	    let correctCount = 0;
219	    let totalObjective = 0;
220	    const attemptAnswers: AttemptAnswer[] = [];
221	
222	    for (const ans of answers) {
223	      const question = await this.questionRepo.findOne({
224	        where: { id: ans.questionId },
225	      });
226	
227	      if (!question) {
228	        throw new NotFoundException(`Question ${ans.questionId} not found`);
229	      }
230	
231	      let isCorrect: boolean | null = null;
232	
233	      if (question.type === QuestionType.OBJECTIVE) {
234	        totalObjective++;
235	
236	        if (ans.selectedOptionId) {
237	          const option = await this.optionRepo.findOne({
238	            where: { id: ans.selectedOptionId },
239	          });
240	
241	          if (option) {
242	            isCorrect = option.is_correct;
243	            if (isCorrect) {
244	              correctCount++;
245	            }
246	          } else {
247	            isCorrect = false;
248	          }
249	        } else {
250	          isCorrect = false;
251	        }
252	      }
253	      // subjective: is_correct remains null
254	
255	      const attemptAnswer = this.answerRepo.create({
256	        attempt_id: attemptId,
257	        question_id: ans.questionId,
258	        selected_option_id: ans.selectedOptionId ?? null,
259	        text_answer: ans.textAnswer ?? null,
260	        is_correct: isCorrect,
261	      });
262	
263	      attemptAnswers.push(attemptAnswer);
264	    }
265	
266	    await this.answerRepo.save(attemptAnswers);
267	
268	    const score =
269	      totalObjective > 0
270	        ? Math.round((correctCount / totalObjective) * 10000) / 100
271	        : null;
272	
273	    attempt.status = AttemptStatus.GRADED;
274	    attempt.graded_at = now;
275	    attempt.submitted_at = now;
276	    attempt.score = score;
277	    attempt.answers = attemptAnswers;
278	
279	    return this.attemptRepo.save(attempt);
280	  }
281	
282	  async redoAttempt(attemptId: string, userId: string): Promise<Attempt> {
283	    const original = await this.attemptRepo.findOne({
284	      where: { id: attemptId },
285	    });
286	
287	    if (!original) {
288	      throw new NotFoundException('Attempt not found');
289	    }
290	
291	    if (original.user_id !== userId) {
292	      throw new BadRequestException('Attempt does not belong to this user');
293	    }
294	
295	    const newAttempt = this.attemptRepo.create({
296	      paper_id: original.paper_id,
297	      user_id: userId,
298	      parent_attempt_id: attemptId,
299	      status: AttemptStatus.IN_PROGRESS,
300	      started_at: new Date(),
301	    });
302	
303	    return this.attemptRepo.save(newAttempt);
304	  }
305	
306	  async getHistory(userId: string): Promise<Attempt[]> {
307	    return this.attemptRepo.find({
308	      where: { user_id: userId },
309	      order: { started_at: 'DESC' },
310	      relations: ['paper'],
311	    });
312	  }
313	
314	  async getPapers(user?: any, storeId?: string): Promise<Paper[]> {
315	    // store_admin: always filter by the JWT's assigned store — the
316	    // caller-supplied `storeId` query param is ignored on purpose.
317	    // Trusting it here would re-introduce the cross-store read leak
318	    // this method is being hardened against.
319	    //
320	    // Everyone else (platform_admin / content_reviewer / auditor):
321	    // keep the existing behavior — optional `storeId` query param
322	    // narrows the listing; omitting it returns all papers.
323	    const scopedStoreId = this.resolveStoreScope(user);
324	    const where: any = {};
325	    if (scopedStoreId) {
326	      where.store_id = scopedStoreId;
327	    } else if (storeId) {
328	      where.store_id = storeId;
329	    }
330	    return this.paperRepo.find({ where, relations: ['paper_questions'] });
331	  }
332	
333	  async getPaper(id: string, user?: any): Promise<Paper> {
334	    const paper = await this.paperRepo.findOne({
335	      where: { id },
336	      relations: ['paper_questions', 'paper_questions.question', 'paper_questions.question.options'],
337	    });
338	
339	    if (!paper) {
340	      throw new NotFoundException('Paper not found');
341	    }
342	
343	    // Tenant-isolation check — for store_admin, a paper in another
344	    // store is indistinguishable from a missing paper (404, not 403).
345	    this.enforcePaperOwnership(paper, user);
346	
347	    return paper;
348	  }
349	}
