1	import {
2	  Entity,
3	  PrimaryGeneratedColumn,
4	  Column,
5	  ManyToOne,
6	  JoinColumn,
7	  OneToMany,
8	} from 'typeorm';
9	import { Paper } from './paper.entity';
10	import { AttemptAnswer } from './attempt-answer.entity';
11	
12	export enum AttemptStatus {
13	  IN_PROGRESS = 'in_progress',
14	  SUBMITTED = 'submitted',
15	  GRADED = 'graded',
16	}
17	
18	@Entity('attempts')
19	export class Attempt {
20	  @PrimaryGeneratedColumn('uuid')
21	  id: string;
22	
23	  @Column({ type: 'uuid' })
24	  paper_id: string;
25	
26	  @ManyToOne(() => Paper)
27	  @JoinColumn({ name: 'paper_id' })
28	  paper: Paper;
29	
30	  @Column({ type: 'uuid' })
31	  user_id: string;
32	
33	  @Column({ type: 'uuid', nullable: true })
34	  parent_attempt_id: string | null;
35	
36	  @ManyToOne(() => Attempt, { nullable: true })
37	  @JoinColumn({ name: 'parent_attempt_id' })
38	  parent_attempt: Attempt | null;
39	
40	  @Column({
41	    type: 'enum',
42	    enum: AttemptStatus,
43	    default: AttemptStatus.IN_PROGRESS,
44	  })
45	  status: AttemptStatus;
46	
47	  @Column({ type: 'decimal', nullable: true })
48	  score: number | null;
49	
50	  @Column({ type: 'timestamptz', nullable: true })
51	  graded_at: Date | null;
52	
53	  @Column({ type: 'timestamptz' })
54	  started_at: Date;
55	
56	  @Column({ type: 'timestamptz', nullable: true })
57	  submitted_at: Date | null;
58	
59	  @OneToMany(() => AttemptAnswer, (aa) => aa.attempt, { cascade: true })
60	  answers: AttemptAnswer[];
61	}
