1	import { randomBytes } from 'crypto';
2	
3	export default () => {
4	  if (!process.env.JWT_SECRET && process.env.NODE_ENV === 'production') {
5	    throw new Error('JWT_SECRET environment variable is required in production');
6	  }
7	  return {
8	    database: {
9	      url: process.env.DATABASE_URL || 'postgres://proctorworks:proctorworks@localhost:5432/proctorworks',
10	    },
11	    jwt: {
12	      secret: process.env.JWT_SECRET || `dev-only-${randomBytes(32).toString('hex')}`,
13	      expiry: process.env.JWT_EXPIRY || '8h',
14	    },
15	    bcrypt: {
16	      rounds: parseInt(process.env.BCRYPT_ROUNDS, 10) || 12,
17	    },
18	    encryption: {
19	      key: process.env.ENCRYPTION_KEY || '0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef',
20	    },
21	    lowStockThreshold: parseInt(process.env.LOW_STOCK_THRESHOLD, 10) || 10,
22	    stalenessThresholdHours: parseInt(process.env.STALENESS_THRESHOLD_HOURS, 10) || 24,
23	    port: parseInt(process.env.PORT, 10) || 3000,
24	  };
25	};
