1	import {
2	  NotFoundException,
3	  BadRequestException,
4	  ForbiddenException,
5	} from '@nestjs/common';
6	import { AssessmentsService } from '../src/assessments/assessments.service';
7	import { AttemptStatus } from '../src/assessments/entities/attempt.entity';
8	import { QuestionType, QuestionStatus } from '../src/questions/entities/question.entity';
9	
10	// ---------------------------------------------------------------------------
11	// Helpers
12	// ---------------------------------------------------------------------------
13	
14	function createMockRepo() {
15	  return {
16	    create: jest.fn((dto) => ({ ...dto })),
17	    save: jest.fn((entity) =>
18	      Array.isArray(entity)
19	        ? Promise.resolve(entity.map((e, i) => ({ id: `saved-${i}`, ...e })))
20	        : Promise.resolve({ id: 'saved-id', ...entity }),
21	    ),
22	    findOne: jest.fn().mockResolvedValue(null),
23	    find: jest.fn().mockResolvedValue([]),
24	    createQueryBuilder: jest.fn(),
25	  };
26	}
27	
28	function buildService(overrides: Record<string, any> = {}) {
29	  const paperRepo = createMockRepo();
30	  const paperQuestionRepo = createMockRepo();
31	  const attemptRepo = createMockRepo();
32	  const answerRepo = createMockRepo();
33	  const questionRepo = createMockRepo();
34	  const optionRepo = createMockRepo();
35	  const dataSource = {} as any;
36	
37	  const repos = {
38	    paperRepo,
39	    paperQuestionRepo,
40	    attemptRepo,
41	    answerRepo,
42	    questionRepo,
43	    optionRepo,
44	    dataSource,
45	    ...overrides,
46	  };
47	
48	  const service = new (AssessmentsService as any)(
49	    repos.paperRepo,
50	    repos.paperQuestionRepo,
51	    repos.attemptRepo,
52	    repos.answerRepo,
53	    repos.questionRepo,
54	    repos.optionRepo,
55	    repos.dataSource,
56	  );
57	
58	  return { service: service as AssessmentsService, ...repos };
59	}
60	
61	// Stub query-builder chain: every chained method returns `this`, getMany resolves
62	function stubQueryBuilder(repo: any, rows: any[]) {
63	  const qb: any = {};
64	  const methods = [
65	    'where',
66	    'andWhere',
67	    'orderBy',
68	    'limit',
69	    'leftJoinAndSelect',
70	    'select',
71	  ];
72	  methods.forEach((m) => (qb[m] = jest.fn().mockReturnValue(qb)));
73	  qb.getMany = jest.fn().mockResolvedValue(rows);
74	  repo.createQueryBuilder.mockReturnValue(qb);
75	  return qb;
76	}
77	
78	// ---------------------------------------------------------------------------
79	// Tests
80	// ---------------------------------------------------------------------------
81	
82	describe('AssessmentsService', () => {
83	  // -----------------------------------------------------------------------
84	  // generatePaper
85	  // -----------------------------------------------------------------------
86	  describe('generatePaper', () => {
87	    it('random type selects random approved questions', async () => {
88	      const questions = [
89	        { id: 'q1', type: QuestionType.OBJECTIVE, status: QuestionStatus.APPROVED },
90	        { id: 'q2', type: QuestionType.SUBJECTIVE, status: QuestionStatus.APPROVED },
91	      ];
92	
93	      const { service, questionRepo, paperRepo, paperQuestionRepo } =
94	        buildService();
95	
96	      const qb = stubQueryBuilder(questionRepo, questions);
97	
98	      paperRepo.save.mockImplementation((entity: any) =>
99	        Promise.resolve({ id: 'paper-1', ...entity }),
100	      );
101	      paperQuestionRepo.save.mockImplementation((entities: any) =>
102	        Promise.resolve(entities),
103	      );
104	
105	      const dto = {
106	        name: 'Random Paper',
107	        generationRule: { type: 'random' as const, count: 2 },
108	      };
109	
110	      const result = await service.generatePaper(dto, {
111	        id: 'user-1',
112	        role: 'platform_admin',
113	      });
114	
115	      // Query builder was called with APPROVED status filter
116	      expect(qb.where).toHaveBeenCalledWith('q.status = :status', {
117	        status: QuestionStatus.APPROVED,
118	      });
119	      // Random ordering applied
120	      expect(qb.orderBy).toHaveBeenCalledWith('RANDOM()');
121	      expect(qb.limit).toHaveBeenCalledWith(2);
122	
123	      // Paper was saved
124	      expect(paperRepo.save).toHaveBeenCalled();
125	
126	      // PaperQuestions created with correct positions
127	      expect(paperQuestionRepo.create).toHaveBeenCalledTimes(2);
128	      expect(paperQuestionRepo.create).toHaveBeenCalledWith(
129	        expect.objectContaining({ question_id: 'q1', position: 1 }),
130	      );
131	      expect(paperQuestionRepo.create).toHaveBeenCalledWith(
132	        expect.objectContaining({ question_id: 'q2', position: 2 }),
133	      );
134	
135	      expect(result.paper_questions).toHaveLength(2);
136	    });
137	
138	    it('rule-based applies filters', async () => {
139	      const questions = [
140	        { id: 'q1', type: QuestionType.OBJECTIVE, status: QuestionStatus.APPROVED },
141	      ];
142	
143	      const { service, questionRepo, paperRepo, paperQuestionRepo } =
144	        buildService();
145	
146	      const qb = stubQueryBuilder(questionRepo, questions);
147	
148	      paperRepo.save.mockImplementation((entity: any) =>
149	        Promise.resolve({ id: 'paper-2', ...entity }),
150	      );
151	      paperQuestionRepo.save.mockImplementation((entities: any) =>
152	        Promise.resolve(entities),
153	      );
154	
155	      const dto = {
156	        name: 'Rule Paper',
157	        generationRule: {
158	          type: 'rule' as const,
159	          count: 5,
160	          filters: { type: QuestionType.OBJECTIVE },
161	        },
162	      };
163	
164	      const result = await service.generatePaper(
165	        dto,
166	        { id: 'user-1', role: 'platform_admin' },
167	        'store-1',
168	      );
169	
170	      expect(qb.where).toHaveBeenCalledWith('q.status = :status', {
171	        status: QuestionStatus.APPROVED,
172	      });
173	      // Store filter applied
174	      expect(qb.andWhere).toHaveBeenCalledWith(
175	        '(q.store_id = :storeId OR q.store_id IS NULL)',
176	        { storeId: 'store-1' },
177	      );
178	      // Type filter applied
179	      expect(qb.andWhere).toHaveBeenCalledWith('q.type = :type', {
180	        type: QuestionType.OBJECTIVE,
181	      });
182	      expect(qb.limit).toHaveBeenCalledWith(5);
183	
184	      // orderBy('RANDOM()') should NOT be called for rule-based
185	      expect(qb.orderBy).not.toHaveBeenCalled();
186	
187	      expect(result.paper_questions).toHaveLength(1);
188	    });
189	
190	    // -----------------------------------------------------------------
191	    // Tenant-isolation: store_admin must NEVER be able to target another
192	    // store via the `?storeId=` query param. The service forces the JWT
193	    // store and rejects an explicit cross-store override.
194	    // -----------------------------------------------------------------
195	    it('store_admin: forces JWT store and ignores caller-supplied storeId override', async () => {
196	      const { service, questionRepo, paperRepo, paperQuestionRepo } =
197	        buildService();
198	      const qb = stubQueryBuilder(questionRepo, []);
199	      paperRepo.save.mockImplementation((entity: any) =>
200	        Promise.resolve({ id: 'paper-x', ...entity }),
201	      );
202	      paperQuestionRepo.save.mockImplementation((entities: any) =>
203	        Promise.resolve(entities),
