628	  // F-P4: Order idempotency lookup must NOT leak across tenant scope
629	  //
630	  // audit_report-1 §5.4 — the original lookup was global by `key`, so
631	  // a caller in store B reusing a key already issued by an actor in
632	  // store A would be served the prior order from store A (cross-tenant
633	  // data leak via predictable key). The fix scopes the lookup by
634	  // (operation_type, actor_id, store_id, key). This test verifies the
635	  // contract end-to-end by:
636	  //   1. having store_admin A create an order with a known key,
637	  //   2. having store_admin B POST a brand-new order with the SAME key,
638	  //   3. asserting B's order is genuinely fresh (different id, store=B,
639	  //      no fields from A's order leak through).
640	  // ──────────────────────────────────────────────────────────────────────
641	  describe('F-P4: Order idempotency cross-tenant non-leakage', () => {
642	    let skuA: string;
643	    let skuB: string;
644	
645	    beforeAll(async () => {
646	      // Each store needs at least one SKU so its store_admin can place
647	      // an order. We deliberately make A and B's prices distinct so a
648	      // leak (same response served back) is loud in the assertions.
649	      const cat = await request(server)
650	        .post('/categories')
651	        .set('Authorization', `Bearer ${adminToken}`)
652	        .send({ name: `IdemCat-${U}` });
653	      const brand = await request(server)
654	        .post('/brands')
655	        .set('Authorization', `Bearer ${adminToken}`)
656	        .send({ name: `IdemBrand-${U}` });
657	
658	      const prodA = await request(server)
659	        .post('/products')
660	        .set('Authorization', `Bearer ${storeAdminAToken}`)
661	        .send({
662	          name: `IdemProdA-${U}`,
663	          categoryId: cat.body.id,
664	          brandId: brand.body.id,
665	        });
666	      const sA = await request(server)
667	        .post(`/products/${prodA.body.id}/skus`)
668	        .set('Authorization', `Bearer ${storeAdminAToken}`)
669	        .send({ skuCode: `IDEM-A-${U}`, priceCents: 7_777 });
670	      skuA = sA.body.id;
671	
672	      const prodB = await request(server)
673	        .post('/products')
674	        .set('Authorization', `Bearer ${storeAdminBToken}`)
675	        .send({
676	          name: `IdemProdB-${U}`,
677	          categoryId: cat.body.id,
678	          brandId: brand.body.id,
679	        });
680	      const sB = await request(server)
681	        .post(`/products/${prodB.body.id}/skus`)
682	        .set('Authorization', `Bearer ${storeAdminBToken}`)
683	        .send({ skuCode: `IDEM-B-${U}`, priceCents: 1_111 });
684	      skuB = sB.body.id;
685	    }, 30_000);
686	
687	    it('same idempotency key in two tenants resolves to two distinct orders', async () => {
688	      const sharedKey = `cross-tenant-idem-${U}`;
689	
690	      // 1. Store A creates an order with the shared key.
691	      const aRes = await request(server)
692	        .post('/orders')
693	        .set('Authorization', `Bearer ${storeAdminAToken}`)
694	        .send({
695	          idempotencyKey: sharedKey,
696	          items: [{ skuId: skuA, quantity: 1 }],
697	        });
698	      expect(aRes.status).toBe(201);
699	      expect(aRes.body.store_id).toBe(storeA.id);

700	      expect(aRes.body.total_cents).toBe(7_777);
701	      const orderAId = aRes.body.id;
702	
703	      // 2. Store B uses the EXACT same idempotency key.
704	      const bRes = await request(server)
705	        .post('/orders')
706	        .set('Authorization', `Bearer ${storeAdminBToken}`)
707	        .send({
708	          idempotencyKey: sharedKey,
709	          items: [{ skuId: skuB, quantity: 1 }],
710	        });
711	      expect(bRes.status).toBe(201);
712	
713	      // 3. Critical: store B must get its OWN fresh order, not store A's.
714	      expect(bRes.body.id).not.toBe(orderAId);
715	      expect(bRes.body.store_id).toBe(storeB.id);
716	      expect(bRes.body.total_cents).toBe(1_111);
717	
718	      // 4. Re-issuing the key inside the SAME tenant must still dedupe.
719	      //    This is the same-scope replay path; it must continue to work.
720	      const aReplay = await request(server)
721	        .post('/orders')
722	        .set('Authorization', `Bearer ${storeAdminAToken}`)
723	        .send({
724	          idempotencyKey: sharedKey,
725	          items: [{ skuId: skuA, quantity: 1 }],
726	        });
727	      expect([200, 201]).toContain(aReplay.status);
728	      expect(aReplay.body.id).toBe(orderAId);
729	      expect(aReplay.body.store_id).toBe(storeA.id);
730	
731	      const bReplay = await request(server)
732	        .post('/orders')
733	        .set('Authorization', `Bearer ${storeAdminBToken}`)
734	        .send({
735	          idempotencyKey: sharedKey,
736	          items: [{ skuId: skuB, quantity: 1 }],
737	        });
738	      expect([200, 201]).toContain(bReplay.status);
739	      expect(bReplay.body.id).toBe(bRes.body.id);
740	      expect(bReplay.body.store_id).toBe(storeB.id);
741	    });
742	  });
