745	  // F-P3: Order promotion resolution must reject cross-store coupons
746	  //
747	  // audit_report-1 §5.3 — `resolvePromotions` previously looked up a
748	  // coupon by code only and applied it without checking that the
749	  // coupon's `store_id` matched the order's store. That allowed a
750	  // store_admin in store B to redeem a coupon issued in store A,
751	  // breaking tenant isolation and enabling cross-store discount abuse.
752	  //
753	  // The fix is enforced inside `resolvePromotions` itself; this test
754	  // exercises the full HTTP path so any regression that re-introduces
755	  // the unscoped lookup is caught at the contract layer.
756	  // ──────────────────────────────────────────────────────────────────────
757	  describe('F-P3: Order promotion cross-store coupon binding', () => {
758	    let storeAProductSkuId: string;
759	    let storeBProductSkuId: string;
760	    const localCouponCode = `LOCAL-${U}`;
761	    const foreignCouponCode = `FOREIGN-${U}`;
762	
763	    beforeAll(async () => {
764	      // Create catalog so each store_admin can place orders against
765	      // their own SKU. The orders service derives `store_id` from the
766	      // caller's JWT, so the SKU's product store doesn't have to match
767	      // — but we keep them aligned for realism.
