773	        .post('/brands')
774	        .set('Authorization', `Bearer ${adminToken}`)
775	        .send({ name: `CrossBrandA-${U}` });
776	      const prodA = await request(server)
777	        .post('/products')
778	        .set('Authorization', `Bearer ${storeAdminAToken}`)
779	        .send({
780	          name: `CrossProdA-${U}`,
781	          categoryId: catA.body.id,
782	          brandId: brandA.body.id,
783	        });
784	      const skuA = await request(server)
785	        .post(`/products/${prodA.body.id}/skus`)
786	        .set('Authorization', `Bearer ${storeAdminAToken}`)
787	        .send({ skuCode: `CROSS-A-${U}`, priceCents: 10_000 });
788	      storeAProductSkuId = skuA.body.id;
789	
790	      const prodB = await request(server)
791	        .post('/products')
792	        .set('Authorization', `Bearer ${storeAdminBToken}`)
793	        .send({
794	          name: `CrossProdB-${U}`,
