797	        });
798	      const skuB = await request(server)
799	        .post(`/products/${prodB.body.id}/skus`)
800	        .set('Authorization', `Bearer ${storeAdminBToken}`)
801	        .send({ skuCode: `CROSS-B-${U}`, priceCents: 10_000 });
802	      storeBProductSkuId = skuB.body.id;
803	
804	      // Promotion + coupon LIVING IN STORE A. The fixed-cents discount
805	      // is generous on purpose so any cross-store leakage shows up
806	      // immediately in the order total.
807	      const promoA = await request(server)
808	        .post('/promotions')
809	        .set('Authorization', `Bearer ${adminToken}`)
810	        .send({
811	          storeId: storeA.id,
812	          name: `CrossPromoA-${U}`,
813	          type: 'threshold',
814	          priority: 100,
815	          discountType: 'fixed_cents',
816	          discountValue: 4_000,
817	        });
818	      await request(server)
819	        .post('/coupons')
820	        .set('Authorization', `Bearer ${adminToken}`)
821	        .send({
822	          storeId: storeA.id,
823	          code: foreignCouponCode,
824	          promotionId: promoA.body.id,
825	          remainingQuantity: 100,
826	        });
827	
828	      // Local promotion + coupon for store B so we can sanity-check
829	      // that the same code path still applies a same-store coupon.
830	      const promoB = await request(server)
831	        .post('/promotions')
832	        .set('Authorization', `Bearer ${adminToken}`)
833	        .send({
834	          storeId: storeB.id,
835	          name: `CrossPromoB-${U}`,
836	          type: 'threshold',
837	          priority: 100,
838	          discountType: 'fixed_cents',
839	          discountValue: 1_500,
840	        });
841	      await request(server)
842	        .post('/coupons')
843	        .set('Authorization', `Bearer ${adminToken}`)
844	        .send({
845	          storeId: storeB.id,
846	          code: localCouponCode,
