41	  ) {}
42	
43	  @Post('lots')
44	  @Roles('store_admin', 'platform_admin')
45	  @ApiOperation({ summary: 'Create an inventory lot' })
46	  @ApiResponse({ status: 201, description: 'Lot created' })
47	  async createLot(
48	    @Body() dto: CreateLotDto,
49	    @CurrentUser() user: any,
50	    @TraceId() traceId?: string,
51	  ) {
52	    const lot = await this.inventoryService.createLot(dto, user);
53	    await this.auditService.log(
54	      user.id,
55	      'create_inventory_lot',
56	      'inventory_lot',
57	      lot.id,
58	      { skuId: dto.skuId },
59	      traceId,
60	    );
61	    return lot;
62	  }
