64	  @Get('lots')
65	  @Roles('store_admin', 'platform_admin')
66	  @ApiOperation({ summary: 'List inventory lots' })
67	  @ApiQuery({ name: 'skuId', required: false, type: 'string' })
68	  @ApiResponse({ status: 200, description: 'List of lots' })
69	  findAllLots(@CurrentUser() user: any, @Query('skuId') skuId?: string) {
70	    return this.inventoryService.findAllLots(user, skuId);
71	  }
72	
73	  @Patch('lots/:id')
74	  @Roles('store_admin', 'platform_admin')
75	  @ApiOperation({ summary: 'Update an inventory lot' })
76	  @ApiParam({ name: 'id', type: 'string', format: 'uuid' })
77	  @ApiResponse({ status: 200, description: 'Lot updated' })
78	  updateLot(
79	    @Param('id', ParseUUIDPipe) id: string,
80	    @Body() dto: Partial<CreateLotDto>,
81	    @CurrentUser() user: any,
82	    @TraceId() traceId?: string,
83	  ) {
84	    const updates: any = {};
85	    if (dto.batchCode !== undefined) updates.batch_code = dto.batchCode;
86	    if (dto.expirationDate !== undefined)
87	      updates.expiration_date = dto.expirationDate;
88	    if (dto.quantity !== undefined) updates.quantity = dto.quantity;
89	    return this.inventoryService.updateLot(id, updates, user).then(async (lot) => {
90	      await this.auditService.log(
91	        user.id,
92	        'update_inventory_lot',
93	        'inventory_lot',
94	        id,
95	        { fields: Object.keys(dto || {}) },
96	        traceId,
97	      );
98	      return lot;
99	    });
