106	  @ApiResponse({ status: 200, description: 'Stock adjusted' })
107	  @ApiResponse({ status: 201, description: 'New adjustment created' })
108	  async adjustStock(
109	    @Body() dto: AdjustStockDto,
110	    @CurrentUser('id') userId: string,
111	    @CurrentUser() user: any,
112	    @Res({ passthrough: true }) res: Response,
113	    @TraceId() traceId?: string,
114	  ) {
115	    const { adjustment, alreadyExisted } =
116	      await this.inventoryService.adjustStock(dto, userId, user);
117	    if (!alreadyExisted) {
118	      res.status(HttpStatus.CREATED);
119	    }
120	    await this.auditService.log(
121	      user.id,
122	      'adjust_inventory_stock',
