22	// Same set the service allowlists against — duplicated as a literal
23	// tuple here so the controller can reject bad input before it ever
24	// hits the service (defense in depth). Keeping it a tuple (rather
25	// than importing a runtime Set) lets us cite the allowed values in
26	// the 400 message without a circular dependency.
27	const ALLOWED_ENTITY_TYPES = [
28	  'products',
29	  'orders',
30	  'questions',
31	  'users',
32	  'inventory',
33	] as const;
34	type AllowedEntityType = (typeof ALLOWED_ENTITY_TYPES)[number];
