37	  /**
38	   * Asserts coupon is currently valid for issuance/redemption: ACTIVE,
39	   * within time window, and (if capped) has remaining_quantity > 0.
40	   * Throws BadRequestException so the caller surfaces a 400, distinct
41	   * from NotFoundException used for tenant scoping.
42	   */
43	  private assertCouponUsable(coupon: Coupon, now: Date = new Date()): void {
44	    if (coupon.status !== CouponStatus.ACTIVE) {
45	      throw new BadRequestException(`Coupon is ${coupon.status}`);
46	    }
47	    if (coupon.starts_at && now < coupon.starts_at) {
48	      throw new BadRequestException('Coupon is not yet active');
49	    }
50	    if (coupon.ends_at && now > coupon.ends_at) {
51	      throw new BadRequestException('Coupon has expired');
52	    }
53	    if (
54	      coupon.remaining_quantity !== null &&
55	      coupon.remaining_quantity !== undefined &&
56	      coupon.remaining_quantity <= 0
57	    ) {
58	      throw new BadRequestException('Coupon has no remaining quantity');
59	    }
60	  }
