62	  private getUserStoreId(user: any): string | null {
63	    return user?.storeId ?? user?.store_id ?? null;
64	  }
65	
66	  private enforceCouponScope(coupon: Coupon, user?: any): void {
67	    if (user?.role !== 'store_admin') {
68	      return;
69	    }
70	    const storeId = this.getUserStoreId(user);
71	    if (!storeId) {
72	      throw new ForbiddenException('Store admin has no assigned store');
73	    }
74	    if (coupon.store_id !== storeId) {
