85	      discount_type: dto.discountType,
86	      discount_value: dto.discountValue,
87	      min_order_cents: dto.minOrderCents ?? null,
88	      starts_at: dto.startsAt ? new Date(dto.startsAt) : null,
89	      ends_at: dto.endsAt ? new Date(dto.endsAt) : null,
90	      redemption_cap: dto.redemptionCap ?? null,
