107	  async claimCoupon(code: string, userId: string): Promise<CouponClaim> {
108	    return this.dataSource.transaction(async (manager) => {
109	      const couponRepo = manager.getRepository(Coupon);
110	      const claimRepo = manager.getRepository(CouponClaim);
111	
112	      const coupon = await couponRepo.findOne({ where: { code } });
113	      if (!coupon) {
114	        throw new NotFoundException('Coupon not found');
115	      }
116	
117	      this.assertCouponUsable(coupon);
118	
119	      const now = new Date();
120	      const savedClaim = await claimRepo.save(
121	        claimRepo.create({
122	          coupon_id: coupon.id,
123	          user_id: userId,
124	          claimed_at: now,
125	        }),
126	      );
127	
128	      if (coupon.remaining_quantity !== null) {
129	        coupon.remaining_quantity -= 1;
130	        if (coupon.remaining_quantity <= 0) {
131	          coupon.status = CouponStatus.EXHAUSTED;
132	        }
133	        await couponRepo.save(coupon);
134	      }
135	
136	      return savedClaim;
137	    });
