140	  async distributeCoupon(
141	    couponId: string,
142	    userIds: string[],
143	    user?: any,
144	  ): Promise<CouponClaim[]> {
145	    if (!Array.isArray(userIds) || userIds.length === 0) {
146	      throw new BadRequestException('userIds must be a non-empty array');
147	    }
148	
149	    return this.dataSource.transaction(async (manager) => {
150	      const couponRepo = manager.getRepository(Coupon);
151	      const claimRepo = manager.getRepository(CouponClaim);
152	
153	      const coupon = await couponRepo.findOne({ where: { id: couponId } });
154	      if (!coupon) {
155	        throw new NotFoundException('Coupon not found');
156	      }
157	      this.enforceCouponScope(coupon, user);
158	
159	      // Distribution must respect the same governance as direct claims:
160	      // status, time window, and remaining quantity (must cover the batch).
161	      this.assertCouponUsable(coupon);
162	      if (
163	        coupon.remaining_quantity !== null &&
164	        coupon.remaining_quantity < userIds.length
165	      ) {
166	        throw new BadRequestException(
167	          `Coupon has only ${coupon.remaining_quantity} remaining; cannot distribute to ${userIds.length} users`,
168	        );
169	      }
170	
171	      const now = new Date();
172	      const claims = userIds.map((uid) =>
173	        claimRepo.create({
174	          coupon_id: couponId,
175	          user_id: uid,
176	          claimed_at: now,
177	        }),
178	      );
179	      const saved = await claimRepo.save(claims);
180	
181	      if (coupon.remaining_quantity !== null) {
182	        coupon.remaining_quantity -= userIds.length;
183	        if (coupon.remaining_quantity <= 0) {
184	          coupon.status = CouponStatus.EXHAUSTED;
185	        }
186	        await couponRepo.save(coupon);
187	      }
188	
189	      return saved;
190	    });
191	  }
