193	  async redeemCoupon(
194	    code: string,
195	    userId: string,
196	    orderId: string,
197	    user?: any,
198	  ): Promise<CouponClaim> {
199	    return this.dataSource.transaction(async (manager) => {
200	      const couponRepo = manager.getRepository(Coupon);
201	      const claimRepo = manager.getRepository(CouponClaim);
202	      const promotionRepo = manager.getRepository(Promotion);
203	
204	      const coupon = await couponRepo.findOne({ where: { code } });
205	      if (!coupon) {
206	        throw new NotFoundException('Coupon not found');
207	      }
208	      this.enforceCouponScope(coupon, user);
209	
210	      // A redemption must respect status + time window. Quantity is not
211	      // checked here because the claim has already drawn from the pool.
212	      if (coupon.status === CouponStatus.EXPIRED) {
213	        throw new BadRequestException('Coupon is expired');
214	      }
215	      const now = new Date();
216	      if (coupon.starts_at && now < coupon.starts_at) {
217	        throw new BadRequestException('Coupon is not yet active');
218	      }
219	      if (coupon.ends_at && now > coupon.ends_at) {
220	        throw new BadRequestException('Coupon has expired');
221	      }
222	
223	      const claim = await claimRepo.findOne({
224	        where: { coupon_id: coupon.id, user_id: userId, redeemed_at: IsNull() },
225	      });
226	      if (!claim) {
227	        throw new NotFoundException('No unredeemed claim found for this user');
228	      }
229	
230	      // Atomically enforce promotion redemption cap and bump count in
231	      // the same UPDATE so concurrent redemptions can't exceed the cap.
232	      const updateResult = await promotionRepo
233	        .createQueryBuilder()
234	        .update(Promotion)
235	        .set({ redemption_count: () => 'redemption_count + 1' })
236	        .where('id = :id', { id: coupon.promotion_id })
237	        .andWhere(
238	          '(redemption_cap IS NULL OR redemption_count < redemption_cap)',
239	        )
240	        .execute();
241	
242	      if (!updateResult.affected || updateResult.affected === 0) {
243	        throw new BadRequestException(
244	          'Promotion redemption cap reached',
245	        );
246	      }
247	
248	      claim.redeemed_at = now;
249	      claim.order_id = orderId;
250	      return claimRepo.save(claim);
251	    });
252	  }
