293	    if (dto.discountValue !== undefined) promo.discount_value = dto.discountValue;
294	    if (dto.minOrderCents !== undefined) promo.min_order_cents = dto.minOrderCents;
295	    if (dto.startsAt !== undefined) promo.starts_at = dto.startsAt ? new Date(dto.startsAt) : null;
296	    if (dto.endsAt !== undefined) promo.ends_at = dto.endsAt ? new Date(dto.endsAt) : null;
297	    if (dto.redemptionCap !== undefined) promo.redemption_cap = dto.redemptionCap;
