302	  async deletePromotion(id: string, storeId?: string): Promise<void> {
303	    const where: any = { id };
304	    if (storeId) where.store_id = storeId;
305	    const promo = await this.promotionRepo.findOne({ where });
306	    if (!promo) throw new NotFoundException('Promotion not found');
307	    await this.promotionRepo.remove(promo);
308	  }
309	
310	  calculateDiscount(promotion: Promotion, orderTotalCents: number): number {
311	    if (
312	      promotion.min_order_cents !== null &&
313	      orderTotalCents < promotion.min_order_cents
314	    ) {
315	      return 0;
316	    }
317	
318	    if (promotion.discount_type === DiscountType.FIXED_CENTS) {
319	      return promotion.discount_value;
320	    }
321	
322	    // percentage
323	    return Math.floor((orderTotalCents * promotion.discount_value) / 100);
324	  }
325	
326	  async resolvePromotions(
327	    orderTotalCents: number,
328	    userId: string,
329	    storeId: string,
330	    couponCode?: string,
331	  ): Promise<ResolvedPromotion> {
332	    const now = new Date();
333	
334	    // 1. Find all active automatic promotions for the store within time window, not capped
335	    const qb = this.promotionRepo
336	      .createQueryBuilder('p')
337	      .where('p.store_id = :storeId', { storeId })
338	      .andWhere('p.active = true')
339	      .andWhere('(p.starts_at IS NULL OR p.starts_at <= :now)', { now })
340	      .andWhere('(p.ends_at IS NULL OR p.ends_at >= :now)', { now })
341	      .andWhere(
342	        '(p.redemption_cap IS NULL OR p.redemption_count < p.redemption_cap)',
343	      );
344	
345	    const autoPromotions = await qb.getMany();
346	
347	    // Filter out first_order promotions if user has prior orders
348	    const filteredPromotions: Promotion[] = [];
349	    for (const promo of autoPromotions) {
350	      if (promo.type === PromotionType.FIRST_ORDER) {
351	        // Check if user has any prior redeemed claims (proxy for orders)
352	        const priorClaim = await this.claimRepo.findOne({
353	          where: { user_id: userId, redeemed_at: MoreThanOrEqual(new Date(0)) },
354	        });
355	        if (priorClaim) {
356	          continue; // skip first_order promo if user has prior orders
357	        }
358	      }
359	      filteredPromotions.push(promo);
360	    }
361	
362	    // 3. Sort by priority DESC
363	    filteredPromotions.sort((a, b) => {
364	      if (b.priority !== a.priority) return b.priority - a.priority;
365	      // 4. Tie-break: highest effective discount
366	      const discA = this.calculateDiscount(a, orderTotalCents);
367	      const discB = this.calculateDiscount(b, orderTotalCents);
368	      if (discB !== discA) return discB - discA;
369	      // 5. Still tied: lower UUID wins
370	      return a.id < b.id ? -1 : 1;
371	    });
372	
373	    const bestAutoPromo = filteredPromotions.length > 0 ? filteredPromotions[0] : null;
374	
375	    // 2. If couponCode provided, validate coupon and get linked promotion.
376	    //
377	    //    Tenant binding (audit_report-1 §5.3): the coupon's `store_id`
378	    //    MUST equal the order's `storeId` before we apply it. Without
379	    //    this check, an attacker could redeem a coupon from a different
380	    //    store against an order in the current store — cross-store
381	    //    discount abuse and a tenant-isolation break. Mismatch is treated
382	    //    as "no coupon" (deterministic, silent: no information is
383	    //    leaked about whether the code exists somewhere else).
384	    let selectedCoupon: Coupon | null = null;
385	    let couponPromotion: Promotion | null = null;
386	
387	    if (couponCode) {
388	      const coupon = await this.couponRepo.findOne({
389	        where: { code: couponCode },
390	        relations: ['promotion'],
391	      });
392	
393	      const storeMatches = !!coupon && coupon.store_id === storeId;
394	
395	      if (
396	        coupon &&
397	        storeMatches &&
398	        coupon.status === CouponStatus.ACTIVE &&
399	        (!coupon.starts_at || coupon.starts_at <= now) &&
400	        (!coupon.ends_at || coupon.ends_at >= now)
401	      ) {
402	        selectedCoupon = coupon;
403	        couponPromotion = coupon.promotion;
404	      } else if (coupon && !storeMatches) {
405	        // Surface the cross-store rejection in operational logs so it's
406	        // visible without throwing — order creation continues without the
407	        // coupon being applied.
408	        this.logger.warn(
409	          `Coupon ${coupon.id} (store=${coupon.store_id}) rejected for order in store ${storeId} — cross-store coupon application blocked.`,
410	        );
411	      }
412	    }
413	
414	    // 8. Max one coupon + one automatic promotion per order
415	    let totalDiscount = 0;
416	    let selectedPromotion: Promotion | null = null;
417	
418	    if (bestAutoPromo) {
419	      const autoDiscount = this.calculateDiscount(bestAutoPromo, orderTotalCents);
420	      if (autoDiscount > 0) {
421	        totalDiscount += autoDiscount;
422	        selectedPromotion = bestAutoPromo;
423	      }
424	    }
425	
426	    if (couponPromotion) {
427	      const couponDiscount = this.calculateDiscount(couponPromotion, orderTotalCents);
428	      if (couponDiscount > 0) {
429	        totalDiscount += couponDiscount;
430	        // If no auto promo was selected, the coupon promotion becomes the selected one
431	        if (!selectedPromotion) {
432	          selectedPromotion = couponPromotion;
433	        }
434	      }
435	    }
436	
437	    return {
438	      selectedPromotion,
439	      selectedCoupon,
440	      totalDiscount,
441	    };
442	  }
443	
444	  @Cron(CronExpression.EVERY_HOUR)
445	  async handleExpiredCoupons(): Promise<void> {
446	    const now = new Date();
447	    const result = await this.couponRepo
448	      .createQueryBuilder()
449	      .update(Coupon)
450	      .set({ status: CouponStatus.EXPIRED })
451	      .where('status = :status', { status: CouponStatus.ACTIVE })
452	      .andWhere('ends_at IS NOT NULL')
453	      .andWhere('ends_at < :now', { now })
454	      .execute();
455	
456	    if (result.affected && result.affected > 0) {
457	      this.logger.log(`Expired ${result.affected} coupons`);
458	    }
459	  }
460	}
