1	import { Injectable } from '@nestjs/common';
2	import { ConfigService } from '@nestjs/config';
3	import { createCipheriv, createDecipheriv, randomBytes } from 'crypto';
4	
5	@Injectable()
6	export class EncryptionService {
7	  private readonly algorithm = 'aes-256-gcm';
8	  private readonly key: Buffer;
9	
10	  constructor(private readonly configService: ConfigService) {
11	    const hex = this.configService.get<string>('encryption.key');
12	    this.key = Buffer.from(hex, 'hex'); // 64 hex chars → 32 bytes
13	  }
14	
15	  encrypt(plaintext: string): string {
16	    const iv = randomBytes(12);
17	    const cipher = createCipheriv(this.algorithm, this.key, iv);
18	    const encrypted = Buffer.concat([
19	      cipher.update(plaintext, 'utf8'),
20	      cipher.final(),
21	    ]);
22	    const tag = cipher.getAuthTag();
23	    // Format: iv:tag:ciphertext (all base64)
24	    return [
25	      iv.toString('base64'),
26	      tag.toString('base64'),
27	      encrypted.toString('base64'),
28	    ].join(':');
29	  }
30	
31	  decrypt(encoded: string): string {
32	    const [ivB64, tagB64, dataB64] = encoded.split(':');
33	    if (!ivB64 || !tagB64 || !dataB64) {
34	      throw new Error('Invalid encrypted format');
35	    }
36	    const iv = Buffer.from(ivB64, 'base64');
37	    const tag = Buffer.from(tagB64, 'base64');
38	    const data = Buffer.from(dataB64, 'base64');
39	
40	    const decipher = createDecipheriv(this.algorithm, this.key, iv);
41	    decipher.setAuthTag(tag);
42	    const decrypted = Buffer.concat([
43	      decipher.update(data),
44	      decipher.final(),
45	    ]);
46	    return decrypted.toString('utf8');
47	  }
48	
49	  isEncrypted(value: string): boolean {
50	    if (!value) return false;
51	    const parts = value.split(':');
52	    return parts.length === 3;
53	  }
54	}
