1	import { EncryptionService } from '../src/common/encryption.service';
2	
3	describe('EncryptionService', () => {
4	  let service: EncryptionService;
5	
6	  beforeAll(() => {
7	    const configService = {
8	      get: (key: string) => {
9	        if (key === 'encryption.key') {
10	          return '00112233445566778899aabbccddeeff00112233445566778899aabbccddeeff';
11	        }
12	        return undefined;
13	      },
14	    };
15	    service = new EncryptionService(configService as any);
16	  });
17	
18	  it('encrypts and decrypts a string round-trip', () => {
19	    const plaintext = 'Sensitive user note: SSN 123-45-6789';
20	    const encrypted = service.encrypt(plaintext);
21	    expect(encrypted).not.toBe(plaintext);
22	    expect(encrypted).toContain(':'); // iv:tag:data format
23	
24	    const decrypted = service.decrypt(encrypted);
25	    expect(decrypted).toBe(plaintext);
26	  });
27	
28	  it('produces different ciphertext for same plaintext (random IV)', () => {
29	    const plaintext = 'Same input';
30	    const a = service.encrypt(plaintext);
31	    const b = service.encrypt(plaintext);
32	    expect(a).not.toBe(b); // different IVs
33	    expect(service.decrypt(a)).toBe(plaintext);
34	    expect(service.decrypt(b)).toBe(plaintext);
35	  });
36	
37	  it('isEncrypted returns true for encrypted format', () => {
38	    const encrypted = service.encrypt('test');
39	    expect(service.isEncrypted(encrypted)).toBe(true);
40	  });
41	
42	  it('isEncrypted returns false for plain text', () => {
43	    expect(service.isEncrypted('just a plain note')).toBe(false);
44	    expect(service.isEncrypted('')).toBe(false);
45	    expect(service.isEncrypted(null as any)).toBe(false);
46	  });
47	
48	  it('decrypt throws on tampered ciphertext', () => {
49	    const encrypted = service.encrypt('secret');
50	    const parts = encrypted.split(':');
51	    parts[2] = 'AAAA' + parts[2].slice(4); // tamper data
52	    expect(() => service.decrypt(parts.join(':'))).toThrow();
53	  });
54	
55	  it('handles unicode and special characters', () => {
56	    const plaintext = '日本語テスト 🔐 <script>alert(1)</script>';
57	    const encrypted = service.encrypt(plaintext);
58	    expect(service.decrypt(encrypted)).toBe(plaintext);
59	  });
60	
61	  it('handles long strings', () => {
62	    const plaintext = 'A'.repeat(10000);
63	    const encrypted = service.encrypt(plaintext);
64	    expect(service.decrypt(encrypted)).toBe(plaintext);
65	  });
66	});
