200	    // Reuse the same ownership guard as paper reads so 404 is returned for
201	    // out-of-scope store_admin access (never 403), matching the tenant
202	    // isolation hiding policy used elsewhere in the module.
203	    this.enforcePaperOwnership(paper, user);
204	
205	    const attempt = this.attemptRepo.create({
206	      paper_id: paperId,
207	      user_id: userId,
208	      status: AttemptStatus.IN_PROGRESS,
209	      started_at: new Date(),
210	    });
211	
212	    return this.attemptRepo.save(attempt);
213	  }
214	
215	  async submitAttempt(
216	    attemptId: string,
217	    answers: SubmitAnswerDto[],
218	    userId: string,
219	  ): Promise<Attempt> {
220	    const attempt = await this.attemptRepo.findOne({
221	      where: { id: attemptId },
222	    });
223	
224	    if (!attempt) {
225	      throw new NotFoundException('Attempt not found');
226	    }
227	
228	    if (attempt.user_id !== userId) {
229	      throw new BadRequestException('Attempt does not belong to this user');
230	    }
231	
232	    if (attempt.status !== AttemptStatus.IN_PROGRESS) {
233	      throw new BadRequestException('Attempt is not in progress');
234	    }
235	
236	    const now = new Date();
237	    let correctCount = 0;
238	    let totalObjective = 0;
239	    const attemptAnswers: AttemptAnswer[] = [];
240	
241	    for (const ans of answers) {
242	      const question = await this.questionRepo.findOne({
243	        where: { id: ans.questionId },
244	      });
245	
246	      if (!question) {
247	        throw new NotFoundException(`Question ${ans.questionId} not found`);
248	      }
249	
250	      let isCorrect: boolean | null = null;
251	
252	      if (question.type === QuestionType.OBJECTIVE) {
253	        totalObjective++;
254	
255	        if (ans.selectedOptionId) {
256	          const option = await this.optionRepo.findOne({
257	            where: { id: ans.selectedOptionId },
258	          });
259	
260	          if (option) {
261	            isCorrect = option.is_correct;
262	            if (isCorrect) {
263	              correctCount++;
264	            }
265	          } else {
266	            isCorrect = false;
267	          }
268	        } else {
269	          isCorrect = false;
270	        }
271	      }
272	      // subjective: is_correct remains null
273	
274	      const attemptAnswer = this.answerRepo.create({
275	        attempt_id: attemptId,
276	        question_id: ans.questionId,
277	        selected_option_id: ans.selectedOptionId ?? null,
278	        text_answer: ans.textAnswer ?? null,
279	        is_correct: isCorrect,
280	      });
281	
282	      attemptAnswers.push(attemptAnswer);
283	    }
284	
285	    await this.answerRepo.save(attemptAnswers);
286	
287	    const score =
288	      totalObjective > 0
289	        ? Math.round((correctCount / totalObjective) * 10000) / 100
290	        : null;
291	
292	    attempt.status = AttemptStatus.GRADED;
293	    attempt.graded_at = now;
294	    attempt.submitted_at = now;
295	    attempt.score = score;
296	    attempt.answers = attemptAnswers;
297	
298	    return this.attemptRepo.save(attempt);
299	  }

