215	  /**
216	   * Start a new attempt on a paper.
217	   *
218	   * Object-level + tenant authorization (audit_report-2 HIGH-1):
219	   *   - store_admin with no assigned store → 403 (resolveStoreScope)
220	   *   - store_admin targeting a paper in another store → 404 (hiding policy,
221	   *     same semantics as paper reads via enforcePaperOwnership)
222	   *   - allowed roles (platform_admin / store_admin / content_reviewer) pass
223	   *     through
224	   *
225	   * Critically, the ownership check runs BEFORE attemptRepo.create so no
226	   * attempt row is ever persisted on the denied path.
227	   */
228	  async startAttempt(paperId: string, user: any): Promise<Attempt> {
229	    const userId: string = user?.id;
230	    const paper = await this.paperRepo.findOne({ where: { id: paperId } });
231	    if (!paper) {
232	      throw new NotFoundException('Paper not found');
233	    }
234	
235	    // Reuse the same ownership guard as paper reads so 404 is returned for
236	    // out-of-scope store_admin access (never 403), matching the tenant
237	    // isolation hiding policy used elsewhere in the module.
238	    this.enforcePaperOwnership(paper, user);
239	
240	    const attempt = this.attemptRepo.create({
241	      paper_id: paperId,
242	      user_id: userId,
243	      status: AttemptStatus.IN_PROGRESS,
244	      started_at: new Date(),
245	    });
246	
247	    return this.attemptRepo.save(attempt);
248	  }
