261	    }
262	
263	    if (attempt.user_id !== userId) {
264	      throw new BadRequestException('Attempt does not belong to this user');
265	    }
266	
267	    if (attempt.status !== AttemptStatus.IN_PROGRESS) {
268	      throw new BadRequestException('Attempt is not in progress');
