27	    private readonly idempotencyRepo: Repository<IdempotencyKey>,
28	    @InjectRepository(Sku)
29	    private readonly skuRepo: Repository<Sku>,
30	    private readonly dataSource: DataSource,
31	    private readonly encryptionService: EncryptionService,
32	    private readonly promotionsService: PromotionsService,
33	  ) {}
34	
35	  private getUserStoreId(user: any): string | null {
36	    return user?.storeId ?? user?.store_id ?? null;
37	  }
38	
39	  private enforceStoreScope(user: any): string | null {
40	    if (user.role === 'store_admin') {
41	      const storeId = this.getUserStoreId(user);
42	      if (!storeId) {
43	        throw new ForbiddenException('Store admin has no assigned store');
44	      }
45	      return storeId;
46	    }
47	    return null;
48	  }
49	
50	  async createOrder(
51	    dto: CreateOrderDto,
52	    user: any,
53	  ): Promise<{ order: Order; alreadyExisted: boolean }> {
54	    // 1. Idempotency check — SCOPED by operation + actor + store.
55	    //
56	    //    audit_report-1 §5.4 — looking up purely by `key` was a
57	    //    cross-tenant leak: a caller in store B reusing a key already
58	    //    issued in store A would get back the prior store-A response.
59	    //    The new lookup binds the key to (operation_type, actor_id,
60	    //    store_id), which is also the shape of the composite UNIQUE
61	    //    index installed by the ScopeIdempotencyKeys1711900000003
62	    //    migration. The same key can now legitimately exist for
63	    //    different actors / stores.
64	    //
65	    //    We pre-resolve the caller's effective store here so the
66	    //    lookup is consistent with the order we'd persist below if
67	    //    the key were new — if the key DOES exist, we additionally
68	    //    re-verify the persisted order's `store_id` against this
69	    //    same scope before returning, as a defense-in-depth check
70	    //    against any row that pre-dates the migration backfill.
71	    const callerStoreId =
72	      this.enforceStoreScope(user) || this.getUserStoreId(user);
73	
74	    const existingKey = await this.idempotencyRepo.findOne({
75	      where: {
76	        operation_type: 'create_order',
77	        actor_id: user.id,
78	        store_id: callerStoreId,
79	        key: dto.idempotencyKey,
80	      },
81	    });
82	    if (existingKey) {
83	      const orderId: string | undefined = existingKey.response_body?.orderId;
84	      if (orderId) {
85	        const existingOrder = await this.orderRepo.findOne({
86	          where: { id: orderId },
87	          relations: ['items'],
88	        });
89	        // Defense-in-depth: even if the index isn't trusted (e.g. a
90	        // legacy unscoped row was matched somehow), refuse to return
91	        // an order that doesn't belong to this caller's store.
92	        if (
93	          existingOrder &&
94	          (callerStoreId == null || existingOrder.store_id === callerStoreId) &&
95	          existingOrder.user_id === user.id
96	        ) {
97	          return { order: existingOrder, alreadyExisted: true };
98	        }
99	      }
100	      // Stored key with mismatched scope — refuse to leak. Treating
101	      // this as NotFound is the safest choice: the caller can retry
102	      // with a fresh key, and no foreign data is exposed.
103	      throw new NotFoundException(
104	        'Idempotency key exists but does not belong to this scope',
105	      );
106	    }
107	
108	    // 2. Look up SKU prices, compute subtotal
109	    const skuIds = dto.items.map((i) => i.skuId);
110	    const skus = await this.skuRepo
111	      .createQueryBuilder('sku')
112	      .whereInIds(skuIds)
113	      .getMany();
114	
115	    const skuMap = new Map<string, Sku>();
116	    for (const sku of skus) {
117	      skuMap.set(sku.id, sku);
118	    }
119	
120	    for (const item of dto.items) {
121	      if (!skuMap.has(item.skuId)) {
122	        throw new NotFoundException(`SKU ${item.skuId} not found`);
123	      }
124	    }
125	
126	    let subtotalCents = 0;
127	    const itemEntries: { skuId: string; quantity: number; unitPriceCents: number }[] = [];
128	    for (const item of dto.items) {
129	      const sku = skuMap.get(item.skuId);
130	      const unitPrice = sku.member_price_cents ?? sku.price_cents;
131	      subtotalCents += unitPrice * item.quantity;
132	      itemEntries.push({
133	        skuId: item.skuId,
134	        quantity: item.quantity,
135	        unitPriceCents: unitPrice,
136	      });
137	    }
138	
139	    // 3. Resolve promotions/coupons (max one auto + one coupon).
140	    //    `callerStoreId` was resolved above for the idempotency lookup;
141	    //    reuse it here so both paths see the exact same scope.
142	    const storeId = callerStoreId;
143	    let discountCents = 0;
144	    let promotionId: string | null = null;
145	    let couponId: string | null = null;
146	
147	    if (storeId) {
148	      const resolved = await this.promotionsService.resolvePromotions(
149	        subtotalCents,
150	        user.id,
151	        storeId,
152	        dto.couponCode,
153	      );
154	      discountCents = resolved.totalDiscount;
155	      promotionId = resolved.selectedPromotion?.id || null;
156	      couponId = resolved.selectedCoupon?.id || null;
157	    }
158	
159	    const totalCents = Math.max(0, subtotalCents - discountCents);
160	
161	    // Encrypt internal notes if provided
162	    const encryptedNotes = dto.internalNotes
163	      ? this.encryptionService.encrypt(dto.internalNotes)
164	      : null;
165	
166	    // 4. Create order + items in transaction
167	    return this.dataSource.transaction(async (manager) => {
168	      const order = manager.create(Order, {
169	        store_id: storeId,
170	        user_id: user.id,
171	        idempotency_key: dto.idempotencyKey,
172	        total_cents: totalCents,
173	        discount_cents: discountCents,
174	        coupon_id: couponId,
175	        promotion_id: promotionId,
176	        internal_notes: encryptedNotes,
177	        status: OrderStatus.PENDING,
178	      });
179	      const savedOrder = await manager.save(order);
180	
181	      const items = itemEntries.map((entry) =>
182	        manager.create(OrderItem, {
183	          order_id: savedOrder.id,
184	          sku_id: entry.skuId,
185	          quantity: entry.quantity,
186	          unit_price_cents: entry.unitPriceCents,
187	        }),
188	      );
189	      await manager.save(items);
190	
191	      // 5. Store idempotency record — scoped by operation + actor + store
192	      //    so different tenants can legitimately reuse the same key
193	      //    without colliding on the lookup, and so the read-back path
194	      //    can never serve a foreign tenant's order.
195	      const idempotencyRecord = manager.create(IdempotencyKey, {
196	        key: dto.idempotencyKey,
197	        operation_type: 'create_order',
198	        actor_id: user.id,
199	        store_id: callerStoreId,
200	        response_body: { orderId: savedOrder.id },
201	      });
202	      await manager.save(idempotencyRecord);
203	
204	      const fullOrder = await manager.findOne(Order, {
205	        where: { id: savedOrder.id },
206	        relations: ['items'],
207	      });
208	
209	      return { order: fullOrder, alreadyExisted: false };
210	    });
211	  }
212	
213	  private findOrderScoped(id: string, user: any): Promise<Order> {
214	    const where: any = { id };
215	    const storeId = this.enforceStoreScope(user);
216	    if (storeId) where.store_id = storeId;
217	    return this.orderRepo.findOne({ where, relations: ['items'] }).then(order => {
218	      if (!order) throw new NotFoundException(`Order ${id} not found`);
219	      return order;
220	    });
221	  }
222	
223	  async confirmOrder(id: string, user?: any): Promise<Order> {
224	    const order = await this.findOrderScoped(id, user || {});
225	    if (order.status !== OrderStatus.PENDING) {
226	      throw new ConflictException(
227	        `Cannot confirm order in status '${order.status}'. Must be 'pending'.`,
228	      );
229	    }
230	    order.status = OrderStatus.CONFIRMED;
231	    return this.orderRepo.save(order);
232	  }
233	
234	  async fulfillOrder(id: string, user?: any): Promise<Order> {
235	    const order = await this.findOrderScoped(id, user || {});
236	    if (order.status !== OrderStatus.CONFIRMED) {
237	      throw new ConflictException(
238	        `Cannot fulfill order in status '${order.status}'. Must be 'confirmed'.`,
239	      );
240	    }
241	    order.status = OrderStatus.FULFILLED;
242	    return this.orderRepo.save(order);
243	  }
244	
245	  async cancelOrder(id: string, user?: any): Promise<Order> {
246	    const order = await this.findOrderScoped(id, user || {});
247	    if (
248	      order.status !== OrderStatus.PENDING &&
249	      order.status !== OrderStatus.CONFIRMED
250	    ) {
251	      throw new ConflictException(
252	        `Cannot cancel order in status '${order.status}'. Must be 'pending' or 'confirmed'.`,
253	      );
254	    }
255	    order.status = OrderStatus.CANCELLED;
256	    return this.orderRepo.save(order);
257	  }
258	
259	  async findAll(user: any): Promise<Order[]> {
260	    const storeId = this.enforceStoreScope(user);
261	    const where: any = {};
262	    if (storeId) where.store_id = storeId;
263	    return this.orderRepo.find({ where, relations: ['items'] });
264	  }
265	
266	  async findById(id: string, user?: any): Promise<Order> {
267	    const order = await this.findOrderScoped(id, user || {});
268	    if (order.internal_notes && this.encryptionService.isEncrypted(order.internal_notes)) {
269	      order.internal_notes = this.encryptionService.decrypt(order.internal_notes);
270	    }
271	    return order;
272	  }
273	
274	  // Cleanup idempotency keys older than 24 hours
275	  private readonly logger = new Logger(OrdersService.name);
276	
277	  @Cron(CronExpression.EVERY_HOUR)
278	  async cleanupExpiredIdempotencyKeys(): Promise<void> {
279	    const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);
280	    const result = await this.idempotencyRepo.delete({
281	      created_at: LessThan(cutoff),
282	    });
283	    if (result.affected > 0) {
284	      this.logger.log(`Cleaned up ${result.affected} expired idempotency keys`);
285	    }
286	  }
287	}
