1	import {
2	  Injectable,
3	  NotFoundException,
4	  ForbiddenException,
5	} from '@nestjs/common';
6	import { InjectRepository } from '@nestjs/typeorm';
7	import { DataSource, Repository } from 'typeorm';
8	import { Question, QuestionType, QuestionStatus } from './entities/question.entity';
9	import { QuestionOption } from './entities/question-option.entity';
10	import { QuestionExplanation } from './entities/question-explanation.entity';
11	import { CreateQuestionDto } from './dto/create-question.dto';
12	import { UpdateQuestionDto } from './dto/update-question.dto';
13	
14	@Injectable()
15	export class QuestionsService {
16	  constructor(
17	    @InjectRepository(Question)
18	    private readonly questionRepo: Repository<Question>,
19	    @InjectRepository(QuestionOption)
20	    private readonly optionRepo: Repository<QuestionOption>,
21	    @InjectRepository(QuestionExplanation)
22	    private readonly explanationRepo: Repository<QuestionExplanation>,
23	    private readonly dataSource: DataSource,
24	  ) {}
25	
26	  private resolveStoreScope(user?: any): string | null {
27	    if (user?.role === 'store_admin') {
28	      const storeId = user?.storeId ?? user?.store_id ?? null;
29	      if (!storeId) {
30	        throw new ForbiddenException('Store admin has no assigned store');
31	      }
32	      return storeId;
33	    }
34	    return null;
35	  }
36	
37	  private enforceQuestionOwnership(question: Question, user?: any): void {
38	    const storeId = this.resolveStoreScope(user);
39	    if (storeId && question.store_id !== storeId) {
40	      throw new NotFoundException('Question not found');
41	    }
42	  }
43	
44	  async createQuestion(
45	    dto: CreateQuestionDto,
46	    userId: string,
47	    user?: any,
48	    storeId?: string,
49	  ): Promise<Question> {
50	    // store_admin: always use their own store, ignore caller-provided storeId
51	    const resolvedStoreId = this.resolveStoreScope(user) ?? storeId ?? null;
52	
53	    const question = this.questionRepo.create({
54	      type: dto.type,
55	      body: dto.body,
56	      created_by: userId,
57	      store_id: resolvedStoreId,
58	    });
59	
60	    const savedQuestion = await this.questionRepo.save(question);
61	
62	    if (dto.type === QuestionType.OBJECTIVE && dto.options?.length) {
63	      const options = dto.options.map((opt) =>
64	        this.optionRepo.create({
65	          question_id: savedQuestion.id,
66	          body: opt.body,
67	          is_correct: opt.isCorrect,
68	        }),
69	      );
70	      savedQuestion.options = await this.optionRepo.save(options);
71	    }
72	
73	    return savedQuestion;
74	  }
75	
76	  async updateQuestion(id: string, dto: UpdateQuestionDto, user?: any): Promise<Question> {
77	    const question = await this.questionRepo.findOne({ where: { id } });
78	    if (!question) {
79	      throw new NotFoundException('Question not found');
80	    }
81	    this.enforceQuestionOwnership(question, user);
82	
83	    if (dto.body !== undefined) question.body = dto.body;
84	    if (dto.type !== undefined) question.type = dto.type;
85	
86	    return this.questionRepo.save(question);
87	  }
88	
89	  async deleteQuestion(id: string, user?: any): Promise<void> {
90	    const question = await this.questionRepo.findOne({ where: { id } });
91	    if (!question) {
92	      throw new NotFoundException('Question not found');
93	    }
94	    this.enforceQuestionOwnership(question, user);
95	    await this.questionRepo.remove(question);
96	  }
97	
98	  async findAll(filters?: {
99	    type?: QuestionType;
100	    status?: QuestionStatus;
101	    storeId?: string;
102	  }, user?: any): Promise<Question[]> {
103	    const where: any = {};
104	    if (filters?.type) where.type = filters.type;
105	    if (filters?.status) where.status = filters.status;
106	
107	    // store_admin: enforce their store scope regardless of query param
108	    const storeId = this.resolveStoreScope(user) ?? filters?.storeId;
109	    if (storeId) where.store_id = storeId;
110	
111	    return this.questionRepo.find({
112	      where,
113	      relations: ['options'],
114	    });
115	  }
116	
117	  async findById(id: string, user?: any): Promise<Question> {
118	    const question = await this.questionRepo.findOne({
119	      where: { id },
120	      relations: ['options', 'explanations'],
121	    });
122	    if (!question) {
123	      throw new NotFoundException('Question not found');
124	    }
125	    this.enforceQuestionOwnership(question, user);
126	    return question;
127	  }
128	
129	  async approveQuestion(id: string, user?: any): Promise<Question> {
130	    const question = await this.questionRepo.findOne({ where: { id } });
131	    if (!question) {
132	      throw new NotFoundException('Question not found');
133	    }
134	    this.enforceQuestionOwnership(question, user);
135	    question.status = QuestionStatus.APPROVED;
136	    return this.questionRepo.save(question);
137	  }
138	
139	  async rejectQuestion(id: string, user?: any): Promise<Question> {
140	    const question = await this.questionRepo.findOne({ where: { id } });
141	    if (!question) {
142	      throw new NotFoundException('Question not found');
143	    }
144	    this.enforceQuestionOwnership(question, user);
145	    question.status = QuestionStatus.REJECTED;
146	    return this.questionRepo.save(question);
147	  }
148	
149	  async addExplanation(
150	    questionId: string,
151	    body: string,
152	    userId: string,
153	    user?: any,
154	  ): Promise<QuestionExplanation> {
155	    const question = await this.questionRepo.findOne({
156	      where: { id: questionId },
157	    });
158	    if (!question) {
159	      throw new NotFoundException('Question not found');
160	    }
161	    this.enforceQuestionOwnership(question, user);
162	
163	    // Auto-increment version_number
164	    const latest = await this.explanationRepo
165	      .createQueryBuilder('e')
166	      .where('e.question_id = :questionId', { questionId })
167	      .orderBy('e.version_number', 'DESC')
168	      .getOne();
169	
170	    const nextVersion = latest ? latest.version_number + 1 : 1;
171	
172	    const explanation = this.explanationRepo.create({
173	      question_id: questionId,
174	      version_number: nextVersion,
175	      body,
176	      created_by: userId,
177	    });
178	
179	    return this.explanationRepo.save(explanation);
180	  }
181	
182	  async getExplanations(questionId: string): Promise<QuestionExplanation[]> {
183	    return this.explanationRepo.find({
184	      where: { question_id: questionId },
185	      order: { version_number: 'ASC' },
186	    });
187	  }
188	
189	  async bulkImport(
190	    questions: CreateQuestionDto[],
191	    userId: string,
192	    user?: any,
193	    storeId?: string,
194	  ): Promise<{ count: number }> {
195	    const resolvedStoreId = this.resolveStoreScope(user) ?? storeId ?? null;
196	    let count = 0;
197	
198	    await this.dataSource.transaction(async (manager) => {
199	      for (const dto of questions) {
200	        const question = manager.create(Question, {
201	          type: dto.type,
202	          body: dto.body,
203	          created_by: userId,
204	          store_id: resolvedStoreId,
205	        });
206	
207	        const savedQuestion = await manager.save(question);
208	
209	        if (dto.type === QuestionType.OBJECTIVE && dto.options?.length) {
210	          const options = dto.options.map((opt) =>
211	            manager.create(QuestionOption, {
212	              question_id: savedQuestion.id,
213	              body: opt.body,
214	              is_correct: opt.isCorrect,
215	            }),
216	          );
217	          await manager.save(options);
218	        }
219	
220	        count++;
221	      }
222	    });
223	
224	    return { count };
225	  }
226	
227	  async bulkExport(filters?: {
228	    type?: QuestionType;
229	    status?: QuestionStatus;
230	    storeId?: string;
231	  }, user?: any): Promise<string> {
232	    const questions = await this.findAll(filters, user);
233	
234	    const header = 'id,type,body,status,options';
235	    const rows = questions.map((q) => {
236	      const escapedBody = `"${q.body.replace(/"/g, '""')}"`;
237	      const optionsJson = q.options?.length
238	        ? `"${JSON.stringify(
239	            q.options.map((o) => ({ body: o.body, isCorrect: o.is_correct })),
240	          ).replace(/"/g, '""')}"`
241	        : '""';
242	      return `${q.id},${q.type},${escapedBody},${q.status},${optionsJson}`;
243	    });
244	
245	    return [header, ...rows].join('\n');
246	  }
247	
248	  async getWrongAnswerStats(
249	    questionId: string,
250	    user?: any,
251	  ): Promise<Record<string, number>> {
252	    const question = await this.questionRepo.findOne({ where: { id: questionId } });
253	    if (!question) {
254	      throw new NotFoundException('Question not found');
255	    }
256	    this.enforceQuestionOwnership(question, user);
257	
258	    const results = await this.dataSource
259	      .createQueryBuilder()
260	      .select('aa.selected_option_id', 'optionId')
261	      .addSelect('COUNT(*)::int', 'count')
262	      .from('attempt_answers', 'aa')
263	      .where('aa.question_id = :questionId', { questionId })
264	      .andWhere('aa.is_correct = false')
265	      .groupBy('aa.selected_option_id')
266	      .getRawMany();
267	
268	    const stats: Record<string, number> = {};
269	    for (const row of results) {
270	      if (row.optionId) {
271	        stats[row.optionId] = row.count;
272	      }
273	    }
274	    return stats;
275	  }
276	}
