20	@Injectable()
21	export class AuthService {
22	  private readonly bcryptRounds: number;
23	
24	  constructor(
25	    @InjectRepository(User)
26	    private readonly userRepository: Repository<User>,
27	    private readonly jwtService: JwtService,
28	    private readonly configService: ConfigService,
29	    private readonly encryptionService: EncryptionService,
30	    private readonly sessionsService: SessionsService,
31	  ) {
32	    this.bcryptRounds = this.configService.get<number>('bcrypt.rounds', 12);
33	  }
34	
35	  /**
36	   * Resolves the JWT lifetime (matching JwtModule.signOptions.expiresIn)
37	   * into an absolute expiry Date so we can persist it on the session row.
38	   * Supports the same suffixes JwtModule accepts: "8h", "30m", "1d", "60s",
39	   * or a bare number-of-seconds.
40	   */
41	  private resolveJwtExpiry(): Date {
42	    const raw = this.configService.get<string>('jwt.expiry', '8h');
43	    const m = /^(\d+)([smhd]?)$/i.exec(String(raw).trim());
44	    let seconds = 8 * 60 * 60;
45	    if (m) {
46	      const n = parseInt(m[1], 10);
47	      const unit = (m[2] || 's').toLowerCase();
48	      const multipliers: Record<string, number> = {
49	        s: 1,
50	        m: 60,
51	        h: 60 * 60,
52	        d: 60 * 60 * 24,
53	      };
54	      seconds = n * (multipliers[unit] ?? 1);
55	    }
56	    return new Date(Date.now() + seconds * 1000);
57	  }
58	
59	  async login(
60	    username: string,
61	    password: string,
62	    context?: { ipAddress?: string; userAgent?: string },
63	  ): Promise<{ accessToken: string; user: { id: string; username: string; role: string } }> {
64	    const user = await this.userRepository.findOne({ where: { username } });
65	    if (!user) {
66	      throw new UnauthorizedException('Invalid credentials');
67	    }
68	
69	    if (user.status === UserStatus.SUSPENDED) {
70	      throw new UnauthorizedException('Account is suspended');
71	    }
72	
73	    // Check lockout
74	    if (user.locked_until && user.locked_until > new Date()) {
75	      throw new UnauthorizedException(
76	        'Account is temporarily locked. Please try again later.',
77	      );
78	    }
79	
80	    // If lock has expired, reset it
81	    if (user.locked_until && user.locked_until <= new Date()) {
82	      user.locked_until = null;
83	      user.failed_login_count = 0;
84	      user.status = UserStatus.ACTIVE;
85	      await this.userRepository.save(user);
86	    }
87	
88	    const isPasswordValid = await bcrypt.compare(password, user.password_hash);
89	
90	    if (!isPasswordValid) {
91	      user.failed_login_count += 1;
92	
93	      if (user.failed_login_count >= 5) {
94	        user.locked_until = new Date(Date.now() + 15 * 60 * 1000); // 15 minutes
95	        user.status = UserStatus.LOCKED;
96	      }
97	
98	      await this.userRepository.save(user);
99	      throw new UnauthorizedException('Invalid credentials');
100	    }
101	
102	    // Reset failed login count on success
103	    if (user.failed_login_count > 0) {
104	      user.failed_login_count = 0;
105	      user.locked_until = null;
106	      user.status = UserStatus.ACTIVE;
107	      await this.userRepository.save(user);
108	    }
109	
110	    // Issue a server-side session that backs this JWT. The jti claim
111	    // links the token to its persisted Session row so logout/admin
112	    // suspension can revoke it on the next request (F-03).
113	    const jti = randomUUID();
114	    const expiresAt = this.resolveJwtExpiry();
115	    await this.sessionsService.createForJti(
116	      user.id,
117	      jti,
118	      expiresAt,
119	      context?.ipAddress,
120	      context?.userAgent,
121	    );
122	
123	    const payload = {
124	      sub: user.id,
125	      username: user.username,
126	      role: user.role,
127	      storeId: user.store_id,
128	      jti,
129	    };
130	
131	    const accessToken = this.jwtService.sign(payload);
132	
133	    return {
134	      accessToken,
135	      user: {
136	        id: user.id,
137	        username: user.username,
138	        role: user.role,
139	      },
140	    };
141	  }
142	
143	  /**
144	   * Logs a user out by invalidating the session row backing the
145	   * presented JWT. Subsequent requests carrying the same token will
146	   * fail in JwtStrategy.validate() with 401.
147	   */
148	  async logout(userId: string, jti: string | undefined): Promise<void> {
149	    if (!jti) {
150	      // Defensive: a token without jti predates this change. We still
151	      // honor logout intent by invalidating *all* active sessions for
152	      // the user, which is the safer policy.
153	      await this.sessionsService.invalidateAllForUser(userId);
154	      return;
155	    }
156	    await this.sessionsService.invalidateByJti(userId, jti);
157	  }
158	
159	  async validateUser(payload: { sub: string }): Promise<User | null> {
160	    return this.userRepository.findOne({ where: { id: payload.sub } });
161	  }
162	
163	  async createUser(dto: CreateUserDto): Promise<User> {
164	    const existing = await this.userRepository.findOne({
165	      where: { username: dto.username },
166	    });
167	    if (existing) {
168	      throw new ConflictException('Username already exists');
169	    }
170	
171	    const passwordHash = await bcrypt.hash(dto.password, this.bcryptRounds);
172	
173	    const user = this.userRepository.create({
174	      username: dto.username,
175	      password_hash: passwordHash,
176	      role: dto.role,
177	      store_id: dto.storeId || null,
178	    });
179	
180	    const saved = await this.userRepository.save(user);
181	
182	    // Remove password_hash from response
183	    delete (saved as any).password_hash;
184	    return saved;
185	  }
186	
187	  async updateUser(id: string, dto: UpdateUserDto): Promise<User> {
188	    const user = await this.userRepository.findOne({ where: { id } });
189	    if (!user) {
190	      throw new NotFoundException('User not found');
191	    }
192	
193	    const previousStatus = user.status;
194	
195	    if (dto.status !== undefined) {
196	      user.status = dto.status;
197	    }
198	    if (dto.role !== undefined) {
199	      user.role = dto.role;
200	    }
201	    if (dto.storeId !== undefined) {
202	      user.store_id = dto.storeId;
203	    }
204	    if (dto.notes !== undefined) {
205	      user.notes = dto.notes ? this.encryptionService.encrypt(dto.notes) : null;
206	    }
207	
208	    const saved = await this.userRepository.save(user);
209	
210	    // If the user is being suspended or locked, invalidate every
211	    // active session so any in-flight tokens stop working immediately.
212	    if (
213	      dto.status !== undefined &&
214	      previousStatus !== dto.status &&
215	      (dto.status === UserStatus.SUSPENDED || dto.status === UserStatus.LOCKED)
216	    ) {
217	      await this.sessionsService.invalidateAllForUser(id);
218	    }
219	
220	    delete (saved as any).password_hash;
221	    return saved;
222	  }
223	
224	  async deleteUser(id: string): Promise<void> {
225	    const user = await this.userRepository.findOne({ where: { id } });
226	    if (!user) {
227	      throw new NotFoundException('User not found');
228	    }
229	    await this.userRepository.remove(user);
230	  }
