232	  async findAll(
233	    page: number = 1,
234	    limit: number = 20,
235	  ): Promise<{ data: User[]; total: number; page: number; limit: number }> {
236	    const [data, total] = await this.userRepository.findAndCount({
237	      skip: (page - 1) * limit,
238	      take: limit,
239	      order: { created_at: 'DESC' },
240	      select: [
241	        'id',
242	        'username',
243	        'role',
244	        'store_id',
245	        'status',
246	        'failed_login_count',
247	        'locked_until',
248	        'created_at',
249	        'updated_at',
250	      ],
251	    });
252	
253	    return { data, total, page, limit };
254	  }
255	
256	  async findById(id: string): Promise<User> {
257	    const user = await this.userRepository.findOne({
258	      where: { id },
259	      select: [
260	        'id',
261	        'username',
262	        'role',
263	        'store_id',
264	        'status',
265	        'failed_login_count',
266	        'locked_until',
267	        'notes',
268	        'created_at',
269	        'updated_at',
270	      ],
271	    });
272	    if (!user) {
273	      throw new NotFoundException('User not found');
274	    }
275	    // Decrypt notes if encrypted
276	    if (user.notes && this.encryptionService.isEncrypted(user.notes)) {
277	      user.notes = this.encryptionService.decrypt(user.notes);
278	    }
279	    return user;
280	  }
281	
282	  async updateNotes(id: string, notes: string): Promise<User> {
283	    const user = await this.userRepository.findOne({ where: { id } });
284	    if (!user) throw new NotFoundException('User not found');
285	    user.notes = this.encryptionService.encrypt(notes);
286	    return this.userRepository.save(user);
287	  }
288	
289	  async changePassword(
290	    userId: string,
291	    currentPassword: string,
292	    newPassword: string,
293	  ): Promise<void> {
294	    const user = await this.userRepository.findOne({ where: { id: userId } });
295	    if (!user) {
296	      throw new NotFoundException('User not found');
297	    }
298	
299	    const isCurrentValid = await bcrypt.compare(
300	      currentPassword,
301	      user.password_hash,
302	    );
303	    if (!isCurrentValid) {
304	      throw new BadRequestException('Current password is incorrect');
305	    }
306	
307	    user.password_hash = await bcrypt.hash(newPassword, this.bcryptRounds);
308	    await this.userRepository.save(user);
309	  }
310	}
