1	import { Injectable, Logger, BadRequestException } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { Repository, DataSource } from 'typeorm';
4	import { Cron, CronExpression } from '@nestjs/schedule';
5	import { ConfigService } from '@nestjs/config';
6	import { DataQualityRule, RuleType } from './entities/data-quality-rule.entity';
7	import { DataQualityScore } from './entities/data-quality-score.entity';
8	import { CreateQualityRuleDto } from './dto/create-quality-rule.dto';
9	import { NotificationsService } from '../notifications/notifications.service';
10	
11	const ENTITY_TABLE_MAP: Record<string, string> = {
12	  products: 'products',
13	  orders: 'orders',
14	  questions: 'questions',
15	  users: 'users',
16	  inventory: 'inventory_lots',
17	};
18	
19	const ALL_ENTITY_TYPES = Object.keys(ENTITY_TABLE_MAP);
20	
21	/**
22	 * Strict allowlist of legal columns per entity_type for quality-rule
23	 * evaluation. Any column referenced in a rule config that does not appear
24	 * here is rejected — this is the security boundary that prevents SQL
25	 * identifier injection in raw query construction.
26	 *
27	 * Allowlists are restricted to columns that are safe to reference in raw
28	 * SQL contexts (no encrypted/sensitive fields). Updating this map requires
29	 * a code change and review.
30	 */
31	const ENTITY_COLUMN_ALLOWLIST: Record<string, ReadonlySet<string>> = {
32	  products: new Set(['id', 'store_id', 'name', 'category_id', 'brand_id', 'status', 'created_at']),
33	  orders: new Set(['id', 'store_id', 'status', 'total_cents', 'discount_cents', 'idempotency_key', 'created_at']),
34	  questions: new Set(['id', 'store_id', 'type', 'body', 'status', 'created_by', 'created_at']),
35	  users: new Set(['id', 'username', 'role', 'store_id', 'status', 'failed_login_count', 'created_at', 'updated_at']),
36	  inventory: new Set(['id', 'sku_id', 'batch_code', 'expiration_date', 'quantity', 'created_at']),
37	};
38	
39	/**
40	 * Identifier shape gate. Even when whitelisted, we re-verify that the
41	 * column name matches a strict snake_case identifier pattern before any
42	 * SQL composition. Defense-in-depth against allowlist bugs.
43	 */
44	const SAFE_IDENTIFIER_RE = /^[a-z_][a-z0-9_]*$/;
45	
46	function assertSafeIdentifier(value: unknown, label: string): string {
47	  if (typeof value !== 'string' || !SAFE_IDENTIFIER_RE.test(value)) {
48	    throw new BadRequestException(
49	      `Invalid ${label}: must match ${SAFE_IDENTIFIER_RE}`,
50	    );
51	  }
52	  return value;
53	}
54	
55	function assertColumnAllowed(
56	  entityType: string,
57	  column: string,
58	  label: string,
59	): string {
60	  assertSafeIdentifier(column, label);
61	  const allowed = ENTITY_COLUMN_ALLOWLIST[entityType];
62	  if (!allowed) {
63	    throw new BadRequestException(`Unknown entity type: ${entityType}`);
64	  }
65	  if (!allowed.has(column)) {
66	    throw new BadRequestException(
67	      `Column "${column}" is not permitted for entity "${entityType}"`,
68	    );
69	  }
70	  return column;
71	}
72	
73	function assertFiniteNumber(value: unknown, label: string): number {
74	  const n = typeof value === 'number' ? value : Number(value);
75	  if (!Number.isFinite(n)) {
76	    throw new BadRequestException(`${label} must be a finite number`);
77	  }
78	  return n;
79	}
