81	@Injectable()
82	export class QualityService {
83	  private readonly logger = new Logger(QualityService.name);
84	
85	  constructor(
86	    @InjectRepository(DataQualityRule)
87	    private readonly ruleRepo: Repository<DataQualityRule>,
88	    @InjectRepository(DataQualityScore)
89	    private readonly scoreRepo: Repository<DataQualityScore>,
90	    private readonly dataSource: DataSource,
91	    private readonly configService: ConfigService,
92	    private readonly notificationsService: NotificationsService,
93	  ) {}
94	
95	  async createRule(dto: CreateQualityRuleDto): Promise<DataQualityRule> {
96	    // Validate config against the column allowlist *before* persisting,
97	    // so malicious or malformed rules never reach the evaluator.
98	    this.validateRuleConfig(dto.entityType, dto.ruleType as RuleType, dto.config);
99	
100	    const rule = this.ruleRepo.create({
101	      entity_type: dto.entityType,
102	      rule_type: dto.ruleType as RuleType,
103	      config: dto.config,
104	    });
105	    return this.ruleRepo.save(rule);
106	  }
107	
108	  /**
109	   * Validates a rule's config against the per-entity column allowlist.
110	   * Throws BadRequestException for any unsafe / unknown column or numeric.
111	   */
112	  private validateRuleConfig(
113	    entityType: string,
114	    ruleType: RuleType,
115	    config: any,
116	  ): void {
117	    if (!ENTITY_TABLE_MAP[entityType]) {
118	      throw new BadRequestException(`Unknown entity type: ${entityType}`);
119	    }
120	    if (!config || typeof config !== 'object') {
121	      throw new BadRequestException('Rule config must be an object');
122	    }
123	
124	    switch (ruleType) {
125	      case RuleType.COMPLETENESS: {
126	        const fields = config.fields;
127	        if (!Array.isArray(fields) || fields.length === 0) {
128	          throw new BadRequestException(
129	            'completeness rule requires a non-empty `fields` array',
130	          );
131	        }
132	        for (const f of fields) {
133	          assertColumnAllowed(entityType, f, 'fields[]');
134	        }
135	        return;
136	      }
137	      case RuleType.RANGE: {
138	        if (config.column === undefined) {
139	          throw new BadRequestException('range rule requires `column`');
140	        }
141	        assertColumnAllowed(entityType, config.column, 'column');
142	        if (config.min !== undefined) assertFiniteNumber(config.min, 'min');
143	        if (config.max !== undefined) assertFiniteNumber(config.max, 'max');
144	        if (config.min === undefined && config.max === undefined) {
145	          throw new BadRequestException(
146	            'range rule requires at least one of `min` or `max`',
147	          );
148	        }
149	        return;
150	      }
151	      case RuleType.UNIQUENESS: {
152	        if (config.column === undefined) {
153	          throw new BadRequestException('uniqueness rule requires `column`');
154	        }
155	        assertColumnAllowed(entityType, config.column, 'column');
156	        return;
157	      }
158	      default:
159	        throw new BadRequestException(`Unknown rule type: ${ruleType}`);
160	    }
161	  }
