167	  async computeScore(entityType: string): Promise<DataQualityScore> {
168	    // Fail fast on bad input *before* issuing a DB query. Invalid entity
169	    // types must return 400, never 500 — raising a plain Error would fall
170	    // through to the global filter as INTERNAL_ERROR.
171	    const tableName = ENTITY_TABLE_MAP[entityType];
172	    if (!tableName) {
173	      throw new BadRequestException(
174	        `Unknown entity type "${entityType}". Allowed: ${ALL_ENTITY_TYPES.join(', ')}.`,
175	      );
176	    }
177	
178	    const rules = await this.ruleRepo.find({
179	      where: { entity_type: entityType, active: true },
180	    });
181	
182	    const ruleScores: number[] = [];
183	
184	    for (const rule of rules) {
185	      const score = await this.evaluateRule(rule, tableName);
186	      ruleScores.push(score);
187	    }
188	
189	    const finalScore =
190	      ruleScores.length > 0
191	        ? ruleScores.reduce((a, b) => a + b, 0) / ruleScores.length
192	        : 100;
193	
194	    const scoreEntity = this.scoreRepo.create({
195	      entity_type: entityType,
196	      score: finalScore,
197	      computed_at: new Date(),
198	    });
199	
200	    return this.scoreRepo.save(scoreEntity);
201	  }
202	
203	  private async evaluateRule(
204	    rule: DataQualityRule,
205	    tableName: string,
206	  ): Promise<number> {
207	    switch (rule.rule_type) {
208	      case RuleType.COMPLETENESS:
209	        return this.evaluateCompleteness(rule, tableName);
210	      case RuleType.RANGE:
211	        return this.evaluateRange(rule, tableName);
212	      case RuleType.UNIQUENESS:
213	        return this.evaluateUniqueness(rule, tableName);
214	      default:
215	        return 100;
216	    }
217	  }
218	
219	  private async evaluateCompleteness(
220	    rule: DataQualityRule,
221	    tableName: string,
222	  ): Promise<number> {
223	    // Re-validate at evaluation time (defense-in-depth) — rules persisted
224	    // before allowlist enforcement, or via direct DB writes, are still
225	    // safely rejected here.
226	    const fieldsRaw: unknown = rule.config?.fields;
227	    if (!Array.isArray(fieldsRaw) || fieldsRaw.length === 0) return 100;
228	
229	    const fields = fieldsRaw.map((f) =>
230	      assertColumnAllowed(rule.entity_type, f as string, 'fields[]'),
231	    );
232	
233	    const safeTable = assertSafeIdentifier(tableName, 'tableName');
234	
235	    const totalResult = await this.dataSource.query(
236	      `SELECT COUNT(*) as total FROM "${safeTable}"`,
237	    );
238	    const total = parseInt(totalResult[0].total, 10);
239	    if (total === 0) return 100;
240	
241	    const conditions = fields
242	      .map((f) => `"${f}" IS NOT NULL AND CAST("${f}" AS TEXT) <> ''`)
243	      .join(' AND ');
244	
245	    const completeResult = await this.dataSource.query(
246	      `SELECT COUNT(*) as complete FROM "${safeTable}" WHERE ${conditions}`,
247	    );
248	    const complete = parseInt(completeResult[0].complete, 10);
249	
250	    return (complete / total) * 100;
251	  }
252	
253	  private async evaluateRange(
254	    rule: DataQualityRule,
255	    tableName: string,
256	  ): Promise<number> {
257	    const rawColumn = rule.config?.column;
258	    if (rawColumn === undefined) return 100;
259	
260	    const column = assertColumnAllowed(rule.entity_type, rawColumn, 'column');
261	    const safeTable = assertSafeIdentifier(tableName, 'tableName');
262	
263	    const totalResult = await this.dataSource.query(
264	      `SELECT COUNT(*) as total FROM "${safeTable}" WHERE "${column}" IS NOT NULL`,
265	    );
266	    const total = parseInt(totalResult[0].total, 10);
267	    if (total === 0) return 100;
268	
269	    const params: any[] = [];
270	    let rangeCondition = `"${column}" IS NOT NULL`;
271	    if (rule.config?.min !== undefined) {
272	      const min = assertFiniteNumber(rule.config.min, 'min');
273	      params.push(min);
274	      rangeCondition += ` AND "${column}" >= $${params.length}`;
275	    }
276	    if (rule.config?.max !== undefined) {
277	      const max = assertFiniteNumber(rule.config.max, 'max');
278	      params.push(max);
279	      rangeCondition += ` AND "${column}" <= $${params.length}`;
280	    }
281	
282	    const inRangeResult = await this.dataSource.query(
283	      `SELECT COUNT(*) as in_range FROM "${safeTable}" WHERE ${rangeCondition}`,
284	      params,
285	    );
286	    const inRange = parseInt(inRangeResult[0].in_range, 10);
287	
288	    return (inRange / total) * 100;
289	  }
290	
291	  private async evaluateUniqueness(
292	    rule: DataQualityRule,
293	    tableName: string,
294	  ): Promise<number> {
295	    const rawColumn = rule.config?.column;
296	    if (rawColumn === undefined) return 100;
297	
298	    const column = assertColumnAllowed(rule.entity_type, rawColumn, 'column');
299	    const safeTable = assertSafeIdentifier(tableName, 'tableName');
300	
301	    const totalResult = await this.dataSource.query(
302	      `SELECT COUNT(*) as total FROM "${safeTable}" WHERE "${column}" IS NOT NULL`,
303	    );
304	    const total = parseInt(totalResult[0].total, 10);
305	    if (total === 0) return 100;
306	
307	    const uniqueResult = await this.dataSource.query(
308	      `SELECT COUNT(DISTINCT "${column}") as unique_count FROM "${safeTable}" WHERE "${column}" IS NOT NULL`,
309	    );
310	    const uniqueCount = parseInt(uniqueResult[0].unique_count, 10);
311	
312	    return (uniqueCount / total) * 100;
313	  }
314	
315	  async getScores(): Promise<DataQualityScore[]> {
316	    return this.dataSource.query(`
317	      SELECT DISTINCT ON (entity_type) *
318	      FROM data_quality_scores
319	      ORDER BY entity_type, computed_at DESC
320	    `);
321	  }
322	
323	  @Cron(CronExpression.EVERY_HOUR)
324	  async recomputeAllScores(): Promise<void> {
325	    this.logger.log('Recomputing all data quality scores');
326	    for (const entityType of ALL_ENTITY_TYPES) {
327	      try {
328	        await this.computeScore(entityType);
329	      } catch (err) {
330	        this.logger.error(
331	          `Failed to compute score for ${entityType}: ${(err as Error).message}`,
332	        );
333	      }
334	    }
335	  }
336	
337	  @Cron(CronExpression.EVERY_HOUR)
338	  async checkFreshness(): Promise<void> {
339	    const thresholdHours =
340	      this.configService.get<number>('stalenessThresholdHours') || 24;
341	
342	    for (const entityType of ALL_ENTITY_TYPES) {
343	      try {
344	        const tableName = ENTITY_TABLE_MAP[entityType];
345	        const safeTable = assertSafeIdentifier(tableName, 'tableName');
346	        const result = await this.dataSource.query(
347	          `
348	          SELECT GREATEST(
349	            MAX(CASE WHEN EXISTS (
350	              SELECT 1 FROM information_schema.columns
351	              WHERE table_name = $1 AND column_name = 'updated_at'
352	            ) THEN updated_at ELSE NULL END),
353	            MAX(created_at)
354	          ) as last_activity
355	          FROM "${safeTable}"
356	        `,
357	          [safeTable],
358	        );
359	
360	        const lastActivity = result[0]?.last_activity;
361	        if (!lastActivity) continue;
362	
363	        const hoursSinceActivity =
364	          (Date.now() - new Date(lastActivity).getTime()) / (1000 * 60 * 60);
365	
366	        if (hoursSinceActivity > thresholdHours) {
367	          await this.notificationsService.createForAdmins(
368	            'data_staleness',
369	            `Data for "${entityType}" has not been updated in ${Math.round(hoursSinceActivity)} hours (threshold: ${thresholdHours}h).`,
370	          );
371	        }
372	      } catch (err) {
373	        this.logger.error(
374	          `Freshness check failed for ${entityType}: ${(err as Error).message}`,
375	        );
376	      }
377	    }
378	  }
379	}
