24	    create: jest.fn((_Entity: any, plain: any) => ({ ...plain })),
25	    save: jest.fn(async (entity: any) => {
26	      if (Array.isArray(entity)) return entity.map((e: any) => ({ ...e, id: 'item-id' }));
27	      return { ...entity, id: 'order-uuid' };
