39	function buildOrder(overrides: Partial<Order> = {}): Order {
40	  return {
41	    id: 'order-uuid',
42	    store_id: 'store-1',
43	    user_id: 'user-1',
44	    status: OrderStatus.PENDING,
45	    idempotency_key: 'idem-1',
46	    total_cents: 1000,
47	    discount_cents: 0,
48	    coupon_id: null as any,
49	    promotion_id: null as any,
50	    internal_notes: null as any,
