59	// Test suite
60	// ---------------------------------------------------------------------------
61	
62	// ---------------------------------------------------------------------------
63	// HIGH-1 — Order entity must NOT carry `unique: true` on idempotency_key
64	// ---------------------------------------------------------------------------
65	//
66	// The previous schema enforced uniqueness on `orders.idempotency_key` at
67	// the table level (via `@Column({ unique: true })`). That conflicts with
68	// the scoped idempotency design — two callers in different stores can
69	// legitimately reuse the same opaque key. This test asserts the entity
70	// metadata so that any future regression that re-adds `unique: true`
71	// (or wraps the column in a single-column @Index({ unique: true }))
72	// fails fast in unit tests, before it ever reaches the migration layer.
73	describe('Order entity metadata', () => {
74	  it('idempotency_key column is not declared unique', () => {
75	    const storage = getMetadataArgsStorage();
76	    const col = storage.columns.find(
77	      (c) => c.target === Order && c.propertyName === 'idempotency_key',
78	    );
79	    expect(col).toBeDefined();
80	    // Either `unique` is not set OR explicitly false. Anything else
81	    // would re-introduce the global UNIQUE constraint that HIGH-1 fixed.
82	    const opts = (col!.options ?? {}) as Record<string, unknown>;
83	    expect(opts.unique === undefined || opts.unique === false).toBe(true);
84	  });
85	
86	  it('no single-column unique @Index covers idempotency_key', () => {
87	    const storage = getMetadataArgsStorage();
88	    const offending = storage.indices.find((idx) => {
89	      if (idx.target !== Order) return false;
90	      if (!idx.unique) return false;
91	      const cols = Array.isArray(idx.columns) ? idx.columns : [];
92	      return cols.length === 1 && cols[0] === 'idempotency_key';
93	    });
94	    expect(offending).toBeUndefined();
95	  });
96	});
