100	  let orderRepo: ReturnType<typeof makeMockRepo>;
101	  let orderItemRepo: ReturnType<typeof makeMockRepo>;
102	  let idempotencyRepo: ReturnType<typeof makeMockRepo>;
103	  let skuRepo: ReturnType<typeof makeMockRepo>;
104	  let dataSource: ReturnType<typeof makeMockDataSource>;
105	  let manager: ReturnType<typeof makeMockManager>;
106	  let encryptionService: {
107	    encrypt: jest.Mock;
108	    decrypt: jest.Mock;
109	    isEncrypted: jest.Mock;
110	  };
111	  let promotionsService: {
112	    resolvePromotions: jest.Mock;
113	  };
114	
115	  beforeEach(() => {
116	    orderRepo = makeMockRepo();
117	    orderItemRepo = makeMockRepo();
118	    idempotencyRepo = makeMockRepo();
119	    skuRepo = makeMockRepo();
120	    manager = makeMockManager();
121	    dataSource = makeMockDataSource(manager);
122	    encryptionService = {
123	      encrypt: jest.fn((value: string) => `enc:${value}`),
124	      decrypt: jest.fn((value: string) => value.replace(/^enc:/, '')),
125	      isEncrypted: jest.fn((value: string) => value.startsWith('enc:')),
126	    };
127	    promotionsService = {
128	      resolvePromotions: jest.fn().mockResolvedValue({
129	        selectedPromotion: null,
130	        selectedCoupon: null,
131	        totalDiscount: 0,
132	      }),
133	    };
134	
135	    service = new OrdersService(
136	      orderRepo as any,
137	      orderItemRepo as any,
138	      idempotencyRepo as any,
139	      skuRepo as any,
140	      dataSource as any,
141	      encryptionService as any,
142	      promotionsService as any,
143	    );
144	  });
145	
146	  // -----------------------------------------------------------------------
147	  // createOrder
148	  // -----------------------------------------------------------------------
149	
150	  describe('createOrder', () => {
151	    const storeAdminUser = { id: 'user-1', role: 'store_admin', store_id: 'store-1' };
152	
153	    it('creates order with correct total computed from SKU prices', async () => {
154	      // No existing idempotency key
155	      idempotencyRepo.findOne.mockResolvedValue(null);
156	
157	      // Two SKUs with different prices
158	      const skuA = { id: 'sku-a', price_cents: 500, member_price_cents: null };
159	      const skuB = { id: 'sku-b', price_cents: 1200, member_price_cents: 1000 };
160	
161	      const qb = {
162	        whereInIds: jest.fn().mockReturnThis(),
163	        getMany: jest.fn().mockResolvedValue([skuA, skuB]),
164	      };
165	      skuRepo.createQueryBuilder.mockReturnValue(qb);
166	
167	      const fullOrder = buildOrder({ total_cents: 2500, items: [] });
168	      manager.findOne.mockResolvedValue(fullOrder);
169	
170	      const dto = {
171	        idempotencyKey: 'new-key',
172	        items: [
173	          { skuId: 'sku-a', quantity: 3 },  // 500 * 3 = 1500
174	          { skuId: 'sku-b', quantity: 1 },  // member_price 1000 * 1 = 1000
175	        ],
176	      };
177	
178	      const result = await service.createOrder(dto, storeAdminUser);
179	
180	      expect(result.alreadyExisted).toBe(false);
181	      expect(result.order).toBeDefined();
182	
183	      // Verify manager.create was called with the correct total
184	      const orderCreateCall = manager.create.mock.calls.find(
185	        ([entity]: any) => entity === Order,
186	      );
187	      expect(orderCreateCall).toBeDefined();
188	      expect(orderCreateCall![1]).toMatchObject({
189	        total_cents: 2500, // 1500 + 1000
190	        discount_cents: 0,
191	        status: OrderStatus.PENDING,
192	        store_id: 'store-1',
193	        user_id: 'user-1',
194	      });
195	    });
196	
197	    it('returns existing order when scoped idempotency key already exists (dedup)', async () => {
198	      // Stored idempotency row carries the orderId in response_body
199	      // and is bound to the same actor + store as the new request.
200	      // Lookup must walk the scoped index and resolve back to the same
201	      // order without re-running the full create transaction.
202	      const existingOrder = buildOrder({
203	        id: 'existing-order-id',
204	        store_id: 'store-1',
205	        user_id: 'user-1',
206	      });
207	
208	      idempotencyRepo.findOne.mockResolvedValue({
209	        id: 'idem-row-id',
210	        operation_type: 'create_order',
211	        actor_id: 'user-1',
212	        store_id: 'store-1',
213	        key: 'dup-key',
214	        response_body: { orderId: 'existing-order-id' },
215	      });
216	      orderRepo.findOne.mockResolvedValue(existingOrder);
217	
218	      const dto = {
219	        idempotencyKey: 'dup-key',
220	        items: [{ skuId: 'sku-a', quantity: 1 }],
221	      };
222	
223	      const result = await service.createOrder(dto, storeAdminUser);
224	
225	      expect(result.alreadyExisted).toBe(true);
226	      expect(result.order).toBe(existingOrder);
227	      // Critical: lookup is by orderId (from response_body), NOT by
228	      // raw idempotency_key — that was the leak surface.
229	      expect(orderRepo.findOne).toHaveBeenCalledWith({
230	        where: { id: 'existing-order-id' },
231	        relations: ['items'],
232	      });
233	      // Idempotency lookup is scoped by operation + actor + store + key.
234	      expect(idempotencyRepo.findOne).toHaveBeenCalledWith({
235	        where: {
236	          operation_type: 'create_order',
237	          actor_id: 'user-1',
238	          store_id: 'store-1',
239	          key: 'dup-key',
240	        },
241	      });
242	      // Transaction should NOT have been invoked on the dedup path.
243	      expect(dataSource.transaction).not.toHaveBeenCalled();
244	    });
245	
246	    // ─────────────────────────────────────────────────────────────────
247	    // audit_report-1 §5.4 — cross-tenant key collision must NOT serve
248	    // a foreign actor / store the existing order. The scoped lookup
249	    // is the primary guard, but we also defensively re-check the
250	    // resolved order's store_id + user_id before returning.
251	    // ─────────────────────────────────────────────────────────────────
252	    it('does NOT return foreign-store order on scoped idempotency lookup miss', async () => {
253	      // The scoped lookup with (actor=user-1, store=store-1) returns
254	      // null — there is no row for THIS scope. The legacy unscoped
255	      // path would have matched a row in store-2 here, leaking it.
256	      idempotencyRepo.findOne.mockResolvedValue(null);
257	
258	      const skuA = { id: 'sku-a', price_cents: 500, member_price_cents: null };
259	      const qb = {
260	        whereInIds: jest.fn().mockReturnThis(),
261	        getMany: jest.fn().mockResolvedValue([skuA]),
262	      };
263	      skuRepo.createQueryBuilder.mockReturnValue(qb);
264	      manager.findOne.mockResolvedValue(buildOrder({ id: 'fresh-order-id' }));
265	
266	      const dto = {
267	        idempotencyKey: 'reused-key',
268	        items: [{ skuId: 'sku-a', quantity: 1 }],
269	      };
270	
271	      const result = await service.createOrder(dto, storeAdminUser);
272	
273	      // A brand-new order is created, and the foreign tenant's row is
274	      // never even fetched.
275	      expect(result.alreadyExisted).toBe(false);
276	      expect(orderRepo.findOne).not.toHaveBeenCalled();
277	      expect(dataSource.transaction).toHaveBeenCalled();
278	    });
279	
280	    it('refuses to return order whose store_id mismatches caller scope (defense-in-depth)', async () => {
281	      // Forced edge case: somehow a row with our scope key resolves to
