            categoryId: cat.body.id,
            brandId: brand.body.id,
          });
        const sku = await request(server)
          .post(`/products/${prod.body.id}/skus`)
          .set('Authorization', `Bearer ${storeAdminAToken}`)
          .send({ skuCode: `P01-A-${U}`, priceCents: 4_242 });
