  // (correct) option per question. Required because P0-4 added a
  // strict "answer.questionId must be in paper" guard, and the
  // paper is generated by random selection — when prior test runs
  // have left other approved questions in the DB, the random pool
  // may pick something other than {q1, q2}. The test now adapts to
  // whatever the random selection actually produced.
  async function fetchPaperAnswerSet(
    pId: string,
    pickWrong: boolean = false,
  ): Promise<{ questionId: string; selectedOptionId: string }[]> {
    const paperRes = await request(server)
      .get(`/papers/${pId}`)
      .set('Authorization', `Bearer ${token}`);
    expect(paperRes.status).toBe(200);
    const paperQuestions: any[] = paperRes.body.paper_questions;
    return paperQuestions.map((pq) => {
      const opts: any[] = pq.question.options;
      const opt = pickWrong
        ? opts.find((o: any) => !o.is_correct)
        : opts.find((o: any) => o.is_correct);
      return { questionId: pq.question_id, selectedOptionId: opt.id };
    });
  }

  it('POST /attempts/:id/submit → graded, score=100', async () => {
    logStep('POST', `/attempts/${attemptId}/submit`);
    const answers = await fetchPaperAnswerSet(paperId, false);
    const res = await request(server).post(`/attempts/${attemptId}/submit`).set('Authorization', `Bearer ${token}`)
      .send({ answers });
    logStep('POST', 'submit', res.status);
    expect(res.status).toBe(201);
    expect(res.body.status).toBe('graded');
    expect(Number(res.body.score)).toBe(100);
  });

  it('POST /attempts/:id/submit on graded → error', async () => {
    logStep('POST', `/attempts/${attemptId}/submit (already graded)`);
    const answers = await fetchPaperAnswerSet(paperId, false);
    const res = await request(server).post(`/attempts/${attemptId}/submit`).set('Authorization', `Bearer ${token}`)
      .send({ answers });
    logStep('POST', 'submit', res.status);
    expect(res.status).toBeGreaterThanOrEqual(400);
  });"}

